    ctx.fillStyle = `rgba(220, 50, 40, ${(0.08 + k * 0.16).toFixed(3)})`; ctx.fill();
    // Pildymo indikatorius — vidinis ratas auga 0→R (kuo arčiau pilnas, tuo arčiau smūgis)
    ctx.beginPath(); ctx.arc(cx, cy, R * k, 0, Math.PI * 2);
