        const homeY = (ally.ry !== undefined) ? ally.ry : ally.y;
        ally._f9AutoEngage = true;
        ally._f9ReturnTarget = ally._f9Target ? { tx: ally._f9Target.tx, ty: ally._f9Target.ty } : { tx: homeX, ty: homeY };
