function _updateFreeMove(now) {
  if (typeof S === 'undefined' || !S || !S.units) return;
  const hero = S.units.find(u => u.team === 0 && u.alive);
  if (!hero) return;

  // Jei vyksta žingsnis — tweeninam rx/ry link target'o
  if (_freeMoveStep) {
    const t = Math.min(1, (now - _freeMoveStep.start) / _FREE_MOVE_STEP_MS);
    hero.rx = _freeMoveStep.srcX + (_freeMoveStep.dstX - _freeMoveStep.srcX) * t;
    hero.ry = _freeMoveStep.srcY + (_freeMoveStep.dstY - _freeMoveStep.srcY) * t;
    if (t >= 1) {
      hero.x = _freeMoveStep.dstX;
      hero.y = _freeMoveStep.dstY;
      hero.rx = hero.x; hero.ry = hero.y;
      hero.px = hero.x; hero.py = hero.y;
      _freeMoveStep = null;
      if (gameMode === 'adventure') {
        S.mana = Math.max(0, (S.mana ?? MANA_MAX) - 1);
        if (typeof updateEnergyHud === 'function') updateEnergyHud();
        const _cleared = S.fullMapRevealed && !S.units.some(u => typeof isHostileAdventureEnemy === 'function' && isHostileAdventureEnemy(u));
        if (!_cleared) {
          S.nanoSteps = (S.nanoSteps || 0) + 1;
        }
        if (S.footsteps) {
          S.footsteps.push({ x: hero.x, y: hero.y, alpha: 1.0 });
          if (S.footsteps.length > 12) S.footsteps.shift();
        }
      }
      // Po žingsnio paleidžiam tick sistemą: priešai juda, energija krenta, fog'as atsidengia
      if (S.phase === 'frozen' && !S.pending[0]) {
        S.pending[0] = { unitId: hero.id, t: 'jump' }; // jump = no-op applySingleAction
        if (gameMode === 'adventure' && typeof aiQueueAction === 'function') {
          aiQueueAction(false);
        }
        if (typeof resolveTick === 'function') resolveTick();
      }
    } else {
      return;
    }
  }

  // Jei eina tick'as — nebradam naujo žingsnio kol neužsibaigė
  if (S.phase !== 'frozen') return;

  // Nevykdomas joks žingsnis — tik iš queue (vienas žingsnis per paspaudimą)
  if (_freeMoveQueue.length === 0) return;
  const { dx, dy } = _freeMoveQueue.shift();
  const nx = hero.x + dx, ny = hero.y + dy;
  if (nx < 0 || nx >= COLS || ny < 0 || ny >= ROWS) return;
  if (typeof isWall === 'function' && isWall(nx, ny)) return;
  if (S.units.some(u => u.alive && u.id !== hero.id && u.x === nx && u.y === ny)) return;

  _freeMoveStep = { srcX: hero.x, srcY: hero.y, dstX: nx, dstY: ny, start: now };
  hero.facing = { dx, dy };
}

document.addEventListener('keyup', e => {
  if (!_freeMoveMode) return;
  if (e.code === 'KeyW') _freeMoveKeys.w = false;
  else if (e.code === 'KeyS') _freeMoveKeys.s = false;
  else if (e.code === 'KeyA') _freeMoveKeys.a = false;
  else if (e.code === 'KeyD') _freeMoveKeys.d = false;
});
// Lango blur — atleidžiam visus klavišus (kad "užstrigęs" klavišas neliktų)
window.addEventListener('blur', () => {
  _freeMoveKeys.w = _freeMoveKeys.a = _freeMoveKeys.s = _freeMoveKeys.d = false;
});


function _createExtraMine() {
  // Hard cap: max 3 mines total (1 primary + 2 extra). Defensive guard against
  // race conditions / direct calls bypassing UI check.
  if (_extraMines.length >= MAX_EXTRA_MINES) return false;
  const idx = _extraMines.length;
  _buildingsRestored = true;   // pastatėm → leidžiam sync (apsauga prieš tuščią overwrite)
  _extraMines.push(_makeMineObj(idx, 1, 1, 100 * (idx + 1), true));
  try { _saveBuildingsState(); } catch (_) {}   // PERSISTENCE — nauja kasykla išsaugoma į Profile
  return true;
}

// Mine objekto fabrikas — naudoja IR build (_createExtraMine) IR restore (_restoreBuildingsState).
// constructing=true → scaffold (nauja statyba); false → jau pastatyta (restore, be scaffold).
function _makeMineObj(idx, level, houseLevel, yOffset, constructing) {
  return {
    idx: idx,
    yOffset: (yOffset != null) ? yOffset : 100 * (idx + 1),
    level: level || 1,
    houseLevel: houseLevel || 1,
    cycle: null,
    shake: { active: false, x: 0, y: 0 },
    squishStart: 0,
    coinParticles: [],
    houseBounds: null,
    stoneBounds: null,
    housePopupOpen: false,
    stonePopupOpen: false,
    houseBtnBounds: null,
    stoneBtnBounds: null,
    constructionStart: constructing ? performance.now() : (performance.now() - 9e8), // 9e8ms praeity = jau pastatyta
    speedUpBtnBounds: null,
    speedUpPopupOpen: false,
    speedUpPopupBtnBounds: null,
    speedUpPopupCloseBounds: null,
    speedUpAnim: null,
  };
}

// ── PASTATŲ (kasyklų) PERSISTENCE ─────────────────────────────────────
// Tampa true tik įėjus į F10 (restore) arba pastačius mine — apsaugo nuo tuščio overwrite.
let _buildingsRestored = false;
// Sync pastatų state į Profile (kviečiama saveProfile metu — visada current).
function _syncBuildingsToProfile() {
  if (typeof Profile === 'undefined' || !Profile) return;
  // RACE GUARD: kol neįėjom į F10 ir _restoreBuildingsState nesuveikė, _extraMines
  // tuščias — NEklobberinam išsaugotų kasyklų (kaip barracksTrained race fix).
  if (!_buildingsRestored) return;
  Profile.buildings = {
    ciucelaLevel: _ciucelaLevel,
    houseLevel: _houseLevel,
    miningLevel: _miningLevel,   // primary mine kasimo lygis (parity su extra mine .level)
    mines: _extraMines.map(function (m) {
      return { idx: m.idx, yOffset: m.yOffset, level: m.level || 1, houseLevel: m.houseLevel || 1 };
    }),
  };
}
function _saveBuildingsState() {
  try { _syncBuildingsToProfile(); } catch (_) {}
  try { if (typeof saveProfile === 'function') saveProfile(); } catch (_) {}
}
// Restore iš Profile — kviečiama įėjus į F10.
function _restoreBuildingsState() {
  try {
    _buildingsRestored = true;   // įėjom į F10 — nuo dabar leidžiam sync net jei buildings tuščias
    var b = (typeof Profile !== 'undefined' && Profile) ? Profile.buildings : null;
    if (!b) return;
    if (typeof b.ciucelaLevel === 'number' && b.ciucelaLevel >= 1) _ciucelaLevel = b.ciucelaLevel;
    if (typeof b.houseLevel === 'number' && b.houseLevel >= 1) _houseLevel = b.houseLevel;
    if (typeof b.miningLevel === 'number' && b.miningLevel >= 1) _miningLevel = b.miningLevel;
    if (Array.isArray(b.mines)) {
      _extraMines.length = 0;
      b.mines.forEach(function (sm, i) {
        if (_extraMines.length >= MAX_EXTRA_MINES) return;
        _extraMines.push(_makeMineObj((sm.idx != null ? sm.idx : i), sm.level, sm.houseLevel, sm.yOffset, false));
      });
    }
  } catch (e) { console.warn('restoreBuildings failed', e); }
}

// ══ OFFLINE PROGRESS ═══════════════════════════════════════════════════
// Idle-game produkcija realiu (wall-clock) laiku: kasimas kaupia RONKE net
// išėjus iš F10 / po reload; treniravimas baigiamas while-away. Statybos
// upgrade'ai jau taikomi iškart (click metu) → persistuoja per buildings.
const _OFFLINE_MAX_MS = 8 * 3600 * 1000;   // max 8h kaupimo (anti-abuse; storage cap dar riboja)

// ── Kasimas (offline RONKE) ───────────────────────────────────────────
// RONKE/sek vienai kasyklai. Tuned ~ atitikti stebimą greitį (cap'as saugo nuo abuse).
function _mineRonkePerSec(level, idx) {
  const base = 0.05;                                    // ~3 RONKE/min lvl1
  const lvlMult = 1 + (Math.max(1, level || 1) - 1) * 0.25;
  const sizeMult = (idx == null) ? 1 : (2 + idx);       // extra kasyklos duoda daugiau (kaip coinCount)
  return base * lvlMult * sizeMult;
}
function _totalMineRonkePerSec() {
  let r = _mineRonkePerSec(_miningLevel, null);         // primary
  try { for (const m of _extraMines) r += _mineRonkePerSec(m.level || 1, m.idx); } catch (_) {}
  return r;
}
// Atsiskaito už praėjusį laiką nuo paskutinio settle. Kviečiama įėjus į F10 + load.
// Kol esam F10 — _bumpIdleMineClock() laiko Profile.idleMineAt = now, tad live ciklas
// ir offline accrual nesidubliuoja (offline skaičiuoja tik away laiką).
function _settleOfflineMining(silent) {
  try {
    if (typeof Profile === 'undefined' || !Profile) return;
    const nowW = Date.now();
    let last = Number(Profile.idleMineAt);
    if (!Number.isFinite(last) || last <= 0) { Profile.idleMineAt = nowW; return; }
    let dt = nowW - last;
    if (dt <= 0) { Profile.idleMineAt = nowW; return; }
    if (dt > _OFFLINE_MAX_MS) dt = _OFFLINE_MAX_MS;
    const rate = _totalMineRonkePerSec();
    let gained = Math.floor(rate * dt / 1000);
    const cap = (typeof _totalHouseCapacity === 'function') ? _totalHouseCapacity() : 30000;
    const space = Math.max(0, cap - _ronkeBalance);
    if (gained > space) gained = space;
    if (gained > 0) {
      _ronkeBalance += gained;
      if (typeof window.updateRonkeBadge === 'function') window.updateRonkeBadge();
      // OFFLINE kasimas TAIP PAT nuima laiką nuo faucet claim (kaip live mine success) — kaupiasi nors žaidimas išjungtas
      try { if (window.RonkeFaucetBoostBulk) window.RonkeFaucetBoostBulk(gained); } catch (_) {}
      if (!silent && typeof showGameNotification === 'function') {
        showGameNotification('WHILE AWAY', '+' + gained + ' RONKE mined', '#ffcf5c');
      }
    }
    Profile.idleMineAt = nowW;
    if (typeof saveProfile === 'function') saveProfile();
  } catch (e) { console.warn('settleOfflineMining failed', e); }
}
function _bumpIdleMineClock() {
  try { if (S.floor === 10 && typeof Profile !== 'undefined' && Profile) Profile.idleMineAt = Date.now(); } catch (_) {}
}

// ── Treniravimas (offline unit completion) ────────────────────────────
// Training EXCLUSIVE (vienu metu tik vienas slot'as) → persistuojam vieną prod.
function _syncBarracksProdToProfile() {
  try {
    if (typeof Profile === 'undefined' || !Profile) return;
    const keys = Object.keys(_barracksProductions);
    if (!keys.length) { Profile.barracksProd = null; return; }
    const slot = parseInt(keys[0], 10);
    const prod = _barracksProductions[slot];
    if (!prod) { Profile.barracksProd = null; return; }
    const elapsedPerf = Math.max(0, performance.now() - prod.startAt);
    Profile.barracksProd = {
      slot: slot,
      queueLeft: prod.queueLeft || 0,
      startWall: Date.now() - elapsedPerf,   // kada prasidėjo DABARTINIS unit (wall-clock)
      produceMs: _BARRACKS_PRODUCE_MS,
    };
  } catch (_) {}
}
let _barracksProdRestored = false;
// Catch-up: užbaigia per away laiką pagamintus unit'us, likusiam queue palieka progresą.
function _restoreBarracksProductions() {
  try {
    if (_barracksProdRestored) return;        // tik kartą per session (reload)
    // Jei jau yra gyva produkcija atmintyje (F10 re-entry mid-session) — neperrašom.
    if (Object.keys(_barracksProductions).length > 0) { _barracksProdRestored = true; return; }
    _barracksProdRestored = true;
    const p = (typeof Profile !== 'undefined' && Profile) ? Profile.barracksProd : null;
    if (!p) return;
    const slot = p.slot | 0;
    if (!_BARRACKS_UNIT_TYPES[slot]) { Profile.barracksProd = null; return; }
    const produceMs = (p.produceMs > 0) ? p.produceMs : _BARRACKS_PRODUCE_MS;
    let elapsed = Date.now() - Number(p.startWall || Date.now());
    if (!(elapsed >= 0)) elapsed = 0;
    if (elapsed > _OFFLINE_MAX_MS) elapsed = _OFFLINE_MAX_MS;
    const totalUnits = (p.queueLeft || 0) + 1;          // dabartinis + likę queue
    let completed = Math.floor(elapsed / produceMs);
    if (completed > totalUnits) completed = totalUnits;
    for (let i = 0; i < completed; i++) { try { _barracksSpawnTrained(slot); } catch (_) {} }
    const remaining = totalUnits - completed;
    if (remaining > 0) {
      let partial = elapsed - completed * produceMs;    // dabartinio unit progresas
      if (partial < 0) partial = 0;
      if (partial > produceMs) partial = produceMs;
      _barracksProductions[slot] = {
        startAt: performance.now() - partial,
        queueLeft: remaining - 1,
        speedUpQueueLeft: 0,
      };
    } else {
      delete _barracksProductions[slot];
      if (Profile) Profile.barracksProd = null;
    }
    _syncBarracksProdToProfile();
    if (typeof saveProfile === 'function') saveProfile();
    if (completed > 0 && typeof showGameNotification === 'function') {
      showGameNotification('WHILE AWAY', '+' + completed + ' unit' + (completed > 1 ? 's' : '') + ' trained', '#7ed957');
    }
  } catch (e) { console.warn('restoreBarracksProductions failed', e); }
}

// ── Ciucela (scarecrow) — vienintelė statyba kuri ATIDEDA level iki pabaigos.
// Persistuojam target+wall-start; restore užbaigia arba tęsia.
function _syncCiucelaConstructionToProfile() {
  try {
    if (typeof Profile === 'undefined' || !Profile) return;
    if (_ciucelaConstructionStart > 0) {
      const elapsedPerf = Math.max(0, performance.now() - _ciucelaConstructionStart);
      Profile.ciucelaConstruction = {
        target: _ciucelaConstructionTargetLevel,
        durMs: _ciucelaConstructionDurMs,
        startWall: Date.now() - elapsedPerf,
      };
    } else {
      Profile.ciucelaConstruction = null;
    }
  } catch (_) {}
}
function _restoreCiucelaConstruction() {
  try {
    const c = (typeof Profile !== 'undefined' && Profile) ? Profile.ciucelaConstruction : null;
    if (!c || !(c.target > 0)) return;
    let elapsed = Date.now() - Number(c.startWall || Date.now());
    if (!(elapsed >= 0)) elapsed = 0;
    const dur = c.durMs > 0 ? c.durMs : 1;
    if (elapsed >= dur) {
      _ciucelaLevel = c.target;                          // baigta while-away
      _ciucelaConstructionStart = 0;
      _ciucelaConstructionTargetLevel = 0;
      _ciucelaConstructionDurMs = 0;
      if (Profile) Profile.ciucelaConstruction = null;
    } else {
      _ciucelaConstructionTargetLevel = c.target;        // tęsiam likusį laiką
      _ciucelaConstructionDurMs = dur;
      _ciucelaConstructionStart = performance.now() - elapsed;
    }
  } catch (e) { console.warn('restoreCiucelaConstruction failed', e); }
}

const _BASE_CONSTRUCTION_MS = 60000;
let _CONSTRUCTION_MS = _BASE_CONSTRUCTION_MS;
const _SPEEDUP_COST = 1;         // TEST: 1 Ronke per minutę (buvo 10)

// ── NFT holder bonus: F10 statybos/treniravimo greitis 2× ─────────────
// Tik jei isHolderEligibleCached() (≥1 NFT laikoma ≥24h server-verified).
// Aktyvinama per `_applyHolderBuildBonus()` kviečiama Wallet onChange + poll.
let _NFT_BUILD_SPEED_MULT = 1.0;
function _applyHolderBuildBonus() {
  const eligible = (window.Wallet && window.Wallet.isHolderEligibleCached)
    ? window.Wallet.isHolderEligibleCached() : false;
  const newMult = eligible ? 0.5 : 1.0;
  if (newMult === _NFT_BUILD_SPEED_MULT) return;
  _NFT_BUILD_SPEED_MULT = newMult;
  _BARRACKS_PRODUCE_MS = Math.round(_BASE_BARRACKS_PRODUCE_MS * newMult);
  _TOWER_PRODUCE_MS = Math.round(_BASE_TOWER_PRODUCE_MS * newMult);
  _CROSSBOW_TOWER_PRODUCE_MS = Math.round(_BASE_CROSSBOW_TOWER_PRODUCE_MS * newMult);
  _ZIP_PRODUCE_MS = Math.round(_BASE_ZIP_PRODUCE_MS * newMult);
  _SLOT_PRODUCE_MS = Math.round(_BASE_SLOT_PRODUCE_MS * newMult);
  _CONSTRUCTION_MS = Math.round(_BASE_CONSTRUCTION_MS * newMult);
  if (typeof logEvent === 'function') {
    logEvent(eligible ? '🏰 NFT holder 2× build speed AKTYVUOTA' : '🏰 NFT holder build bonus išjungtas', 'info');
  }
}
// Hook onto Wallet (load order safe — Wallet declares onChange in wallet.js init).
document.addEventListener('DOMContentLoaded', () => {
  if (window.Wallet && window.Wallet.onChange) {
    window.Wallet.onChange(() => _applyHolderBuildBonus());
  }
  // Poll every 30s in case async getNftHoldStatus completes after onChange fired.
  setInterval(_applyHolderBuildBonus, 30000);
});
const _houseConstructionImg = new Image();
_houseConstructionImg.src = 'assets_tiny/House_Construction.png';
const _pawnHammerImg = new Image();
_pawnHammerImg.src = 'assets_tiny/Pawn_Interact_Hammer.png';
// Lvl 2 mine — 2 frames (frame 0 = lemputė ON, frame 1 = lemputė OFF), switch kas 20s.
// Frames stabilizuoti per bottom-center anchor (FOOT_Y=372 abiejuose).
const _lvl2MineImg = new Image();
_lvl2MineImg.src = 'assets_tiny/lvl2mine.png'; // legacy fallback
const _lvl2MineSheet = new Image();
_lvl2MineSheet.src = 'assets_tiny/lvl2mine01.png';
const _LVL2_FW = 320, _LVL2_FH = 380, _LVL2_FRAMES = 2;
const _LVL2_FRAME_MS = 20000; // 20s ON → 20s OFF → loop
function _lvl2FrameIndex(now) {
  return Math.floor((now || 0) / _LVL2_FRAME_MS) % _LVL2_FRAMES;
}
function _drawLvl2Mine(ctx, dx, dy, dw, dh, now) {
  const sheet = _lvl2MineSheet;
  if (sheet && sheet.complete && sheet.naturalWidth > 0) {
    const fi = _lvl2FrameIndex(now);
    ctx.drawImage(sheet, fi * _LVL2_FW, 0, _LVL2_FW, _LVL2_FH, dx, dy, dw, dh);
    return true;
  }
  if (_lvl2MineImg.complete && _lvl2MineImg.naturalWidth > 0) {
    ctx.drawImage(_lvl2MineImg, dx, dy, dw, dh);
    return true;
  }
  return false;
}

// Vykdo kasimo ciklą konkrečiai extra kasyklai (panašus į _runMiningCycle, bet be global state)
function _runExtraMineCycle(mine, now) {
  const mc = mine.cycle;
  if (!mc) return;
  const SZ = 90, PAM_SZ = 50;
  const WALK_SPD = 105, MINE_DUR = 4000;
  const elapsed = now - mc.phaseStart;
  const walkDist = Math.hypot(mc.stoneWx - mc.homeWx, mc.stoneWy - mc.homeWy);
  // 2-ra kasykla (idx 0) +1s lėtesnis, 3-ia (idx 1) +2s, ir t.t. (tiek ėjimas, tiek nešimas)
  const walkDur = (walkDist / WALK_SPD) * 1000 + (mine.idx + 1) * 1000;
  const lerp = (a, b, t) => a + (b - a) * Math.max(0, Math.min(1, t));
  const faceRight = mc.stoneWx >= mc.homeWx;
  const mineWx = mc.stoneWx - 30;

  const draw = (img, frames, fw, fps, wx, wy, sz, facingRight) => {
    if (!img.complete || !img.naturalWidth) return;
    const frame = Math.floor(now / (1000 / fps)) % frames;
    const drawY = wy - SZ + (sz < SZ ? 34 : 20);
    const px = wx - sz / 2;
    ctx.save();
    ctx.imageSmoothingEnabled = false;
    if (!facingRight) {
      ctx.scale(-1, 1);
      ctx.drawImage(img, frame * fw, 0, fw, 192, -px - sz, drawY, sz, sz);
    } else {
      ctx.drawImage(img, frame * fw, 0, fw, 192, px, drawY, sz, sz);
    }
    ctx.restore();
  };

  if (mc.phase === 'walk_to_stone') {
    const t = Math.min(elapsed / walkDur, 1);
    draw(_pawnRunImg, 6, 192, 8,
      lerp(mc.homeWx, mineWx, t),
      lerp(mc.homeWy, mc.stoneWy, t),
      SZ, faceRight);
    if (t >= 1) { mc.phase = 'mining'; mc.phaseStart = now; }
  } else if (mc.phase === 'mining') {
    draw(_pawnInteractImg, 6, 192, 10, mineWx, mc.stoneWy, SZ, faceRight);
    const hitCycle = Math.floor(elapsed / 600);
    const hitPhase = (elapsed % 600) / 600;
    const shakeX = hitCycle >= 1 && hitPhase < 0.25 ? Math.sin(hitPhase * Math.PI * 8) * 3 : 0;
    mine.shake.active = true; mine.shake.x = shakeX; mine.shake.y = 0;
    if (elapsed > MINE_DUR) {
      mine.shake.active = false; mine.shake.x = 0; mine.shake.y = 0;
      if (Math.random() < _mineSuccessChance(mine.level)) {
        mc.phase = 'pam_walk_to_house'; mc.phaseStart = now;
      } else {
        mc.phase = 'idle_at_stone'; mc.phaseStart = now;
        mc.idleDur = 3000 + Math.random() * 2000;
        // FAIL text — pozicija iš stone pixel koordinačių
        spawnDmgNumber(mc.stoneWx / CELL, mc.stoneWy / CELL, 'FAIL', '#ff3333', 11, 'miss');
      }
    }
  } else if (mc.phase === 'idle_at_stone') {
    draw(_pawnIdleImg, 8, 192, 6, mineWx, mc.stoneWy, SZ, faceRight);
    if (elapsed > mc.idleDur) { mc.phase = 'mining'; mc.phaseStart = now; }
  } else if (mc.phase === 'pam_walk_to_house') {
    const t = Math.min(elapsed / walkDur, 1);
    draw(_pamNpcImg, 19, 192, 12,
      lerp(mineWx, mc.homeWx, t),
      lerp(mc.stoneWy, mc.homeWy, t),
      PAM_SZ, !faceRight);
    if (t >= 1) {
      const coinCount = 2 + mine.idx;  // 2nd mine=+2, 3rd=+3, 4th=+4...
      _ronkeBalance += coinCount;
      for (let i = 0; i < coinCount; i++) {
        mine.coinParticles.push({
          wx: mc.homeWx - 40 + i * 20,
          wy: mc.homeWy - 95,
          born: now + i,
        });
      }
      mine.squishStart = now;
      mc.phase = 'walk_to_stone'; mc.phaseStart = now;
    }
  }
}

// Bendras house upgrade popup renderer — naudojamas primary ir kiekvienam extra mine.
// Grąžina { btnBounds } (arba btnBounds=null, jei max level pasiektas).
function _drawHouseUpgradePopup(anchor, level, isConstructing) {
  const nextLvl = level + 1;
  const nextCost = _nextHouseCost(level);
  const isMax = nextCost === null;
  const pw = 148;
  const headerH = 24;
  const ph = isConstructing ? 64 : (isMax ? 72 : 108);
  const rad = 6;
  let px = Math.round(anchor.x + anchor.w / 2 - pw / 2);
  let py = Math.round(anchor.y - ph - 12);
  const PAD = 6;
  const v = _getVisibleWorldRect();
  px = Math.max(v.x + PAD, Math.min(v.x + v.w - pw - PAD, px));
  py = Math.max(v.y + PAD, Math.min(v.y + v.h - ph - PAD, py));
  const rr = (x, y, w, h, r) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.arcTo(x + w, y,     x + w, y + h, r);
    ctx.arcTo(x + w, y + h, x,     y + h, r);
    ctx.arcTo(x,     y + h, x,     y,     r);
    ctx.arcTo(x,     y,     x + w, y,     r);
    ctx.closePath();
  };
  ctx.save();
  ctx.fillStyle = 'rgba(0,0,0,0.55)';
  rr(px + 2, py + 4, pw, ph, rad); ctx.fill();
  ctx.fillStyle = '#161a22';
  rr(px, py, pw, ph, rad); ctx.fill();
  ctx.save();
  rr(px, py, pw, ph, rad); ctx.clip();
  ctx.fillStyle = '#b08a2e';
  ctx.fillRect(px, py, pw, headerH);
  ctx.fillStyle = 'rgba(0,0,0,0.35)';
  ctx.fillRect(px, py + headerH - 2, pw, 2);
  ctx.restore();
  ctx.lineWidth = 1.5;
  ctx.strokeStyle = '#ffe97a';
  rr(px + 0.5, py + 0.5, pw - 1, ph - 1, rad); ctx.stroke();
  // Title
  ctx.fillStyle = '#1a1506';
  ctx.font = 'bold 11px monospace';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  const _title = isMax ? `HOUSE — Lv.${level} (MAX)` : `HOUSE — Lv.${level} → Lv.${nextLvl}`;
  ctx.fillText(_title, px + pw / 2, py + headerH / 2);

  let btnBounds = null;
  const curCap = _houseCapacity(level);
  const nextCap = _houseCapacity(nextLvl);

  if (isConstructing) {
    ctx.fillStyle = '#ffd47a';
    ctx.font = 'bold 11px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.lineWidth = 3;
    ctx.strokeStyle = 'rgba(0,0,0,0.55)';
    ctx.strokeText('Under construction...', px + pw / 2, py + headerH + 18);
    ctx.fillText('Under construction...', px + pw / 2, py + headerH + 18);
  } else {
    const sx = px + 10;
    const valX = px + pw - 10;
    const syStat = py + headerH + 12;
    ctx.fillStyle = '#8a92a0';
    ctx.font = 'bold 10px monospace';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';
    ctx.fillText('STORAGE', sx, syStat);
    ctx.font = 'bold 12px monospace';
    ctx.textAlign = 'right';
    ctx.lineWidth = 3;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)';
    const _val = isMax ? `${curCap}` : `${curCap} → ${nextCap}`;
    ctx.fillStyle = isMax ? '#c8d0e0' : '#7effa0';
    ctx.strokeText(_val, valX, syStat);
    ctx.fillText(_val, valX, syStat);

    if (!isMax) {
      // Cost row + button
      const costLabel = String(nextCost);
      ctx.font = 'bold 12px monospace';
      const costW = ctx.measureText(costLabel).width;
      const iconSz = 16, gapC = 5;
      const rowW = iconSz + gapC + costW;
      const rowX = px + pw / 2 - rowW / 2;
      const rowY = syStat + 14;
      const fr = Math.floor(performance.now() / 90) % 8;
      const thumb = _getRonkeCoinThumb(iconSz, fr);
      if (thumb) ctx.drawImage(thumb, rowX, rowY);
      const canAfford = _ronkeBalance >= nextCost;
      ctx.fillStyle = canAfford ? '#ffe066' : '#ff8a7a';
      ctx.textAlign = 'left';
      ctx.textBaseline = 'middle';
      ctx.lineWidth = 3;
      ctx.strokeStyle = 'rgba(0,0,0,0.6)';
      ctx.strokeText(costLabel, rowX + iconSz + gapC, rowY + iconSz / 2);
      ctx.fillText(costLabel, rowX + iconSz + gapC, rowY + iconSz / 2);
      // UPGRADE button
      const bw2 = 112, bh2 = 22;
      const bxU = px + pw / 2 - bw2 / 2;
      const byU = py + ph - bh2 - 7;
      const hoverBtn = _worldMx >= bxU && _worldMx <= bxU + bw2 && _worldMy >= byU && _worldMy <= byU + bh2;
      ctx.fillStyle = !canAfford ? '#2d3a2d' : (hoverBtn ? '#6ec56e' : '#4e9e4e');
      rr(bxU, byU, bw2, bh2, 5); ctx.fill();
      ctx.lineWidth = 1.5;
      ctx.strokeStyle = !canAfford ? '#5a6e5a' : (hoverBtn ? '#d4ffd4' : '#a8f0a8');
      rr(bxU + 0.5, byU + 0.5, bw2 - 1, bh2 - 1, 5); ctx.stroke();
      ctx.fillStyle = canAfford ? '#fff' : '#aaa';
      ctx.font = 'bold 11px monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.lineWidth = 2;
      ctx.strokeStyle = 'rgba(0,0,0,0.55)';
      ctx.strokeText('UPGRADE', bxU + bw2 / 2, byU + bh2 / 2 + 1);
      ctx.fillText('UPGRADE', bxU + bw2 / 2, byU + bh2 / 2 + 1);
      btnBounds = { x: bxU, y: byU, w: bw2, h: bh2 };
    }
  }
  // Close X
  const cxSz = 12;
  const cxX = px + pw - cxSz - 5;
  const cxY = py + 6;
  const hovX = _worldMx >= cxX && _worldMx <= cxX + cxSz && _worldMy >= cxY && _worldMy <= cxY + cxSz;
  ctx.fillStyle = hovX ? '#ff6e6e' : 'rgba(0,0,0,0.3)';
  rr(cxX, cxY, cxSz, cxSz, 2); ctx.fill();
  ctx.strokeStyle = '#fff';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(cxX + 3, cxY + 3); ctx.lineTo(cxX + cxSz - 3, cxY + cxSz - 3);
  ctx.moveTo(cxX + cxSz - 3, cxY + 3); ctx.lineTo(cxX + 3, cxY + cxSz - 3);
  ctx.stroke();
  ctx.restore();
  return btnBounds;
}

// Bendras stone (mining) upgrade popup renderer.
// level — dabartinis mining lygis; costMul — kainos multiplikatorius (1.0 primary, 1.5 extras).
function _drawStoneUpgradePopup(anchor, level, costMul) {
  const nextLvl = level + 1;
  const isMax = _nextMiningCost(level) === null;
  const curPct  = Math.round(_mineSuccessChance(level) * 100);
  const nextPct = Math.round(_mineSuccessChance(nextLvl) * 100);
  const miningCost = isMax ? 0 : Math.ceil(_nextMiningCost(level) * costMul);
  const pw = 148;
  const headerH = 24;
  const ph = 108;
  const rad = 6;
  let px = Math.round(anchor.x + anchor.w / 2 - pw / 2);
  let py = Math.round(anchor.y - ph - 14);
  const PAD = 6;
  const v = _getVisibleWorldRect();
  px = Math.max(v.x + PAD, Math.min(v.x + v.w - pw - PAD, px));
  py = Math.max(v.y + PAD, Math.min(v.y + v.h - ph - PAD, py));
  const rr = (x, y, w, h, r) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.arcTo(x + w, y,     x + w, y + h, r);
    ctx.arcTo(x + w, y + h, x,     y + h, r);
    ctx.arcTo(x,     y + h, x,     y,     r);
    ctx.arcTo(x,     y,     x + w, y,     r);
    ctx.closePath();
  };
  ctx.save();
  // Drop shadow
  ctx.fillStyle = 'rgba(0,0,0,0.55)';
  rr(px + 2, py + 4, pw, ph, rad); ctx.fill();
  // Panel bg
  ctx.fillStyle = '#1a1410';
  rr(px, py, pw, ph, rad); ctx.fill();
  // Header
  ctx.save();
  rr(px, py, pw, ph, rad); ctx.clip();
  ctx.fillStyle = '#b08a2e';
  ctx.fillRect(px, py, pw, headerH);
  ctx.fillStyle = 'rgba(0,0,0,0.35)';
  ctx.fillRect(px, py + headerH - 2, pw, 2);
  ctx.restore();
  // Border
  ctx.lineWidth = 1.5;
  ctx.strokeStyle = '#ffe97a';
  rr(px + 0.5, py + 0.5, pw - 1, ph - 1, rad);
  ctx.stroke();
  // Title
  ctx.fillStyle = '#1a1506';
  ctx.font = 'bold 11px monospace';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(isMax ? ('MINE \u2014 Lv.' + level + ' (MAX)') : ('MINE \u2014 Lv.' + level + ' \u2192 Lv.' + nextLvl), px + pw / 2, py + headerH / 2);
  // SUCCESS stat row
  const statX = px + 10;
  const statR = px + pw - 10;
  let rowY = py + headerH + 12;
  ctx.font = 'bold 10px monospace';
  ctx.textAlign = 'left';
  ctx.textBaseline = 'middle';
  ctx.fillStyle = '#8a92a0';
  ctx.fillText('SUCCESS', statX, rowY);
  ctx.font = 'bold 12px monospace';
  ctx.textAlign = 'right';
  ctx.lineWidth = 3;
  ctx.strokeStyle = 'rgba(0,0,0,0.6)';
  const successStr = isMax ? (curPct + '% (MAX)') : (curPct + '% \u2192 ' + nextPct + '%');
  ctx.fillStyle = '#7effa0';
  ctx.strokeText(successStr, statR, rowY);
  ctx.fillText(successStr, statR, rowY);
  // Cost row + UPGRADE button — tik jei NE max level
  let _btnBounds = null;
  if (isMax) {
    ctx.fillStyle = '#ffe066';
    ctx.font = 'bold 12px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.lineWidth = 3;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)';
    ctx.strokeText('MAX LEVEL', px + pw / 2, rowY + 30);
    ctx.fillText('MAX LEVEL', px + pw / 2, rowY + 30);
  } else {
    // Cost row (centered)
    const iconSz = 16, gapC = 5;
    const costLabel = String(miningCost);
    ctx.font = 'bold 12px monospace';
    const costW = ctx.measureText(costLabel).width;
    const rowW = iconSz + gapC + costW;
    const rowX = px + pw / 2 - rowW / 2;
    const rowCY = rowY + 16;
    const fr = Math.floor(performance.now() / 90) % 8;
    const thumb = _getRonkeCoinThumb(iconSz, fr);
    if (thumb) ctx.drawImage(thumb, rowX, rowCY);
    const canAfford = _ronkeBalance >= miningCost;
    ctx.fillStyle = canAfford ? '#ffe066' : '#d48a8a';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';
    ctx.lineWidth = 3;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)';
    ctx.strokeText(costLabel, rowX + iconSz + gapC, rowCY + iconSz / 2);
    ctx.fillText(costLabel, rowX + iconSz + gapC, rowCY + iconSz / 2);
    // UPGRADE button
    const bw2 = 112, bh2 = 22;
    const bxU = px + pw / 2 - bw2 / 2;
    const byU = py + ph - bh2 - 7;
    const hoverBtn = _worldMx >= bxU && _worldMx <= bxU + bw2 && _worldMy >= byU && _worldMy <= byU + bh2;
    ctx.fillStyle = !canAfford ? '#2d3a2d' : (hoverBtn ? '#6ec56e' : '#4e9e4e');
    rr(bxU, byU, bw2, bh2, 5); ctx.fill();
    ctx.lineWidth = 1.5;
    ctx.strokeStyle = !canAfford ? '#5a6e5a' : (hoverBtn ? '#d4ffd4' : '#a8f0a8');
    rr(bxU + 0.5, byU + 0.5, bw2 - 1, bh2 - 1, 5); ctx.stroke();
    ctx.fillStyle = canAfford ? '#fff' : '#aaa';
    ctx.font = 'bold 11px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.lineWidth = 2;
    ctx.strokeStyle = 'rgba(0,0,0,0.55)';
    ctx.strokeText('UPGRADE', bxU + bw2 / 2, byU + bh2 / 2 + 1);
    ctx.fillText('UPGRADE', bxU + bw2 / 2, byU + bh2 / 2 + 1);
    _btnBounds = { x: bxU, y: byU, w: bw2, h: bh2 };
  }
  // Close X
  const cxSz = 12;
  const cxX = px + pw - cxSz - 5;
  const cxY = py + 6;
  const hovX = _worldMx >= cxX && _worldMx <= cxX + cxSz && _worldMy >= cxY && _worldMy <= cxY + cxSz;
  ctx.fillStyle = hovX ? '#ff6e6e' : 'rgba(0,0,0,0.3)';
  rr(cxX, cxY, cxSz, cxSz, 2); ctx.fill();
  ctx.strokeStyle = '#fff';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(cxX + 3, cxY + 3); ctx.lineTo(cxX + cxSz - 3, cxY + cxSz - 3);
  ctx.moveTo(cxX + cxSz - 3, cxY + 3); ctx.lineTo(cxX + 3, cxY + cxSz - 3);
  ctx.stroke();
  ctx.restore();
  return _btnBounds;
}

// Čiučela mana-regen ubgreidimo popup. Grąžina { upgrade, close } button bounds.
function _drawCiucelaUpgradePopup(anchor, isConstructing) {
  const cur  = _ciucelaCurrent();
  const next = _ciucelaNext();
  const isMax = !next;
  const pw = 168;
  const ph = isConstructing ? 96 : (isMax ? 84 : 116);
  const headerH = 24;
  const rad = 6;
  let px = Math.round(anchor.x + anchor.w / 2 - pw / 2);
  let py = Math.round(anchor.y - ph - 12 + 40);
  const PAD = 6;
  const v = _getVisibleWorldRect();
  px = Math.max(v.x + PAD, Math.min(v.x + v.w - pw - PAD, px));
  py = Math.max(v.y + PAD, Math.min(v.y + v.h - ph - PAD, py));
  const rr = (x, y, w, h, r) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.arcTo(x + w, y,     x + w, y + h, r);
    ctx.arcTo(x + w, y + h, x,     y + h, r);
    ctx.arcTo(x,     y + h, x,     y,     r);
    ctx.arcTo(x,     y,     x + w, y,     r);
    ctx.closePath();
  };
  ctx.save();
  // Drop shadow + body
  ctx.fillStyle = 'rgba(0,0,0,0.55)';
  rr(px + 2, py + 4, pw, ph, rad); ctx.fill();
  ctx.fillStyle = '#161a22';
  rr(px, py, pw, ph, rad); ctx.fill();
  // Header (gold band)
  ctx.save();
  rr(px, py, pw, ph, rad); ctx.clip();
  ctx.fillStyle = '#b08a2e';
  ctx.fillRect(px, py, pw, headerH);
  ctx.fillStyle = 'rgba(0,0,0,0.35)';
  ctx.fillRect(px, py + headerH - 2, pw, 2);
  ctx.restore();
  ctx.lineWidth = 1.5;
  ctx.strokeStyle = '#ffe97a';
  rr(px + 0.5, py + 0.5, pw - 1, ph - 1, rad); ctx.stroke();
  // Title
  ctx.fillStyle = '#1a1506';
  ctx.font = 'bold 11px monospace';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  const _ttl = isConstructing
    ? `SCARECROW — Lv.${cur.level} → Lv.${_ciucelaConstructionTargetLevel}`
    : (isMax ? `SCARECROW — Lv.${cur.level} (MAX)` : `SCARECROW — Lv.${cur.level} → Lv.${next.level}`);
  ctx.fillText(_ttl, px + pw / 2, py + headerH / 2);
  // Stats: mana regen rate
  const sx = px + 10;
  const valX = px + pw - 10;
  const sy0 = py + headerH + 16;
  ctx.fillStyle = '#8a92a0';
  ctx.font = 'bold 10px monospace';
  ctx.textAlign = 'left';
  ctx.fillText('MANA / SEC', sx, sy0);
  ctx.textAlign = 'right';
  const _curRate = (1000 / cur.manaMs).toFixed(2);
  const _showNext = next || _CIUCELA_TIERS[Math.min(_ciucelaConstructionTargetLevel - 1, _CIUCELA_TIERS.length - 1)];
  const _val = isConstructing
    ? `${_curRate} → ${(1000 / _showNext.manaMs).toFixed(2)}`
    : (isMax ? `${_curRate}` : `${_curRate} → ${(1000 / next.manaMs).toFixed(2)}`);
  ctx.fillStyle = isMax && !isConstructing ? '#c8d0e0' : '#7effa0';
  ctx.font = 'bold 12px monospace';
  ctx.lineWidth = 3;
  ctx.strokeStyle = 'rgba(0,0,0,0.6)';
  ctx.strokeText(_val, valX, sy0);
  ctx.fillText(_val, valX, sy0);
  let upBtn = null;
  if (isConstructing) {
    // Progress bar + remaining seconds
    const _now = performance.now();
    const _prog = Math.min(1, (_now - _ciucelaConstructionStart) / Math.max(1, _ciucelaConstructionDurMs));
    const _secLeft = Math.max(0, Math.ceil((_ciucelaConstructionDurMs - (_now - _ciucelaConstructionStart)) / 1000));
    const barW = pw - 24, barH = 8;
    const barX = px + 12;
    const barY = py + ph - barH - 14;
    ctx.fillStyle = 'rgba(0,0,0,0.55)';
    ctx.fillRect(barX - 1, barY - 1, barW + 2, barH + 2);
    ctx.fillStyle = '#3a2f1a';
    ctx.fillRect(barX, barY, barW, barH);
    ctx.fillStyle = '#ffd766';
    ctx.fillRect(barX, barY, barW * _prog, barH);
    ctx.fillStyle = '#ffe9a8';
    ctx.font = 'bold 10px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'bottom';
    ctx.lineWidth = 2;
    ctx.strokeStyle = 'rgba(0,0,0,0.7)';
    const mm = Math.floor(_secLeft / 60), ss = _secLeft % 60;
    const timeStr = mm > 0 ? `${mm}:${String(ss).padStart(2,'0')}` : `${_secLeft}s`;
    ctx.strokeText(`BUILDING ${timeStr}`, px + pw / 2, barY - 2);
    ctx.fillText(`BUILDING ${timeStr}`, px + pw / 2, barY - 2);
  } else if (!isMax) {
    // Cost row
    const iconSz = 16, gapC = 5;
    const costLabel = String(next.cost);
    ctx.font = 'bold 12px monospace';
    const costW = ctx.measureText(costLabel).width;
    const rowW = iconSz + gapC + costW;
    const rowX = px + pw / 2 - rowW / 2;
    const rowY = sy0 + 14;
    const fr = Math.floor(performance.now() / 90) % 8;
    const thumb = _getRonkeCoinThumb(iconSz, fr);
    if (thumb) ctx.drawImage(thumb, rowX, rowY);
    const canAfford = _ronkeBalance >= next.cost;
    ctx.fillStyle = canAfford ? '#ffe066' : '#d48a8a';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';
    ctx.lineWidth = 3;
    ctx.strokeStyle = 'rgba(0,0,0,0.6)';
    ctx.strokeText(costLabel, rowX + iconSz + gapC, rowY + iconSz / 2);
    ctx.fillText(costLabel, rowX + iconSz + gapC, rowY + iconSz / 2);
    // UPGRADE button
    const bw = 124, bh = 22;
    const bxU = px + pw / 2 - bw / 2;
    const byU = py + ph - bh - 8;
    const hov = _worldMx >= bxU && _worldMx <= bxU + bw && _worldMy >= byU && _worldMy <= byU + bh;
    ctx.fillStyle = !canAfford ? '#2d3a4a' : (hov ? '#5ebbc5' : '#4a9da6');
    rr(bxU, byU, bw, bh, 5); ctx.fill();
    ctx.lineWidth = 1.5;
    ctx.strokeStyle = !canAfford ? '#5a6e7a' : (hov ? '#d4f3ff' : '#a8e0e8');
    rr(bxU + 0.5, byU + 0.5, bw - 1, bh - 1, 5); ctx.stroke();
    ctx.fillStyle = canAfford ? '#fff' : '#aaa';
    ctx.font = 'bold 11px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.lineWidth = 2;
    ctx.strokeStyle = 'rgba(0,0,0,0.55)';
    ctx.strokeText('UPGRADE', bxU + bw / 2, byU + bh / 2 + 1);
    ctx.fillText('UPGRADE', bxU + bw / 2, byU + bh / 2 + 1);
    upBtn = { x: bxU, y: byU, w: bw, h: bh };
  }
  // Close X
  const cxSz = 12;
  const cxX = px + pw - cxSz - 5;
  const cxY = py + 6;
  const hovX = _worldMx >= cxX && _worldMx <= cxX + cxSz && _worldMy >= cxY && _worldMy <= cxY + cxSz;
  ctx.fillStyle = hovX ? '#ff6e6e' : 'rgba(0,0,0,0.3)';
  rr(cxX, cxY, cxSz, cxSz, 2); ctx.fill();
  ctx.strokeStyle = '#fff';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(cxX + 3, cxY + 3); ctx.lineTo(cxX + cxSz - 3, cxY + cxSz - 3);
  ctx.moveTo(cxX + cxSz - 3, cxY + 3); ctx.lineTo(cxX + 3, cxY + cxSz - 3);
  ctx.stroke();
  ctx.restore();
  return { upgrade: upBtn, close: { x: cxX, y: cxY, w: cxSz, h: cxSz } };
}

// Ronke2 radial menu — EVE Online stilius. Center = hero. Return: { cx, cy, innerR, outerR, items }.
function _drawRonkeRadialMenu(anchor) {
  const cx = anchor.x + anchor.w / 2;
  const cy = anchor.y + anchor.h / 2;
  const innerR = 34, outerR = 82;
  const idleOn = _ronkeIdleMode;
  const items = [
    { id: 'attack',   label: 'ATTACK',   icon: '\u2694', col: '#9c3a1a', hov: '#c65a3a' },
    { id: 'pullback', label: 'PULLBACK', icon: '\u21A9', col: '#1a4a8c', hov: '#3a6abc' },
    { id: 'idle',     label: idleOn ? 'IDLE ON' : 'IDLE OFF', icon: idleOn ? '\u25A0' : '\u25B6',
      col: idleOn ? '#b87a3c' : '#4e9e4e', hov: idleOn ? '#d48a4c' : '#6ec56e' },
  ];
  const N = items.length;
  const step = (Math.PI * 2) / N;
  const start = -Math.PI / 2 - step / 2; // pirma wedge ant viršaus

  // Hover testas (world space, radial menu centras world coords)
  const mdx = (_worldMx ?? -9999) - cx;
  const mdy = (_worldMy ?? -9999) - cy;
  const mR = Math.sqrt(mdx * mdx + mdy * mdy);
  const hoverInRing = mR >= innerR && mR <= outerR;

  ctx.save();
  // Drop shadow
  ctx.beginPath(); ctx.arc(cx + 3, cy + 4, outerR, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(0,0,0,0.45)'; ctx.fill();

  for (let i = 0; i < N; i++) {
    const a0 = start + i * step;
    const a1 = a0 + step;
    items[i].a0 = a0; items[i].a1 = a1;
    // Hover for this wedge
    let mAng = Math.atan2(mdy, mdx);
    while (mAng < a0) mAng += Math.PI * 2;
    while (mAng > a1 + Math.PI * 2) mAng -= Math.PI * 2;
    const hov = hoverInRing && mAng >= a0 && mAng <= a1;
    items[i].hover = hov;
    // Wedge path (donut slice)
    const pad = 0.025;
    ctx.beginPath();
    ctx.arc(cx, cy, outerR, a0 + pad, a1 - pad);
    ctx.arc(cx, cy, innerR, a1 - pad, a0 + pad, true);
    ctx.closePath();
    ctx.fillStyle = hov ? items[i].hov : items[i].col;
    ctx.fill();
    ctx.lineWidth = 2; ctx.strokeStyle = '#1a1506'; ctx.stroke();
    // Icon + label
    const midA = (a0 + a1) / 2;
    const midR = (innerR + outerR) / 2;
    const tx = cx + Math.cos(midA) * midR;
    const ty = cy + Math.sin(midA) * midR;
    ctx.fillStyle = '#fff';
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.lineWidth = 2.5; ctx.strokeStyle = 'rgba(0,0,0,0.6)';
    ctx.font = 'bold 20px monospace';
    ctx.strokeText(items[i].icon, tx, ty - 10);
    ctx.fillText(items[i].icon, tx, ty - 10);
    ctx.font = 'bold 10px monospace';
    ctx.strokeText(items[i].label, tx, ty + 12);
    ctx.fillText(items[i].label, tx, ty + 12);
  }

  // Center — close X
  const hovClose = mR < innerR;
  ctx.beginPath(); ctx.arc(cx, cy, innerR - 2, 0, Math.PI * 2);
  ctx.fillStyle = hovClose ? '#3a2020' : 'rgba(22,28,38,0.95)';
  ctx.fill();
  ctx.lineWidth = 2; ctx.strokeStyle = hovClose ? '#ff8080' : '#666'; ctx.stroke();
  ctx.strokeStyle = '#fff'; ctx.lineWidth = 2.5;
  ctx.beginPath();
  ctx.moveTo(cx - 10, cy - 10); ctx.lineTo(cx + 10, cy + 10);
  ctx.moveTo(cx + 10, cy - 10); ctx.lineTo(cx - 10, cy + 10);
  ctx.stroke();
  ctx.restore();
  return { cx, cy, innerR, outerR, items };
}
function _radialMenuHit(menu, mx, my) {
  if (!menu) return null;
  const dx = mx - menu.cx, dy = my - menu.cy;
  const r = Math.sqrt(dx * dx + dy * dy);
  if (r < menu.innerR) return 'close';
  if (r > menu.outerR) return null;
  let ang = Math.atan2(dy, dx);
  for (const it of menu.items) {
    let a = ang;
    while (a < it.a0) a += Math.PI * 2;
    while (a > it.a1 + Math.PI * 2) a -= Math.PI * 2;
    if (a >= it.a0 && a <= it.a1) return it.id;
  }
  return null;
}

function _drawConstructionInfoPopup(anchor, mine, now) {
  const pw = 174, ph = 114, rad = 7;
  let px = Math.round(anchor.x + anchor.w / 2 - pw / 2);
  let py = Math.round(anchor.y - ph - 14);
  const PAD = 6;
  const v = _getVisibleWorldRect();
  px = Math.max(v.x + PAD, Math.min(v.x + v.w - pw - PAD, px));
  py = Math.max(v.y + PAD, Math.min(v.y + v.h - ph - PAD, py));
  const rr = (x, y, w, h, r) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.arcTo(x + w, y,     x + w, y + h, r);
    ctx.arcTo(x + w, y + h, x,     y + h, r);
    ctx.arcTo(x,     y + h, x,     y,     r);
    ctx.arcTo(x,     y,     x + w, y,     r);
    ctx.closePath();
  };
  ctx.save();
  ctx.fillStyle = 'rgba(0,0,0,0.45)';
  rr(px + 3, py + 4, pw, ph, rad); ctx.fill();
  ctx.fillStyle = '#1f242f';
  rr(px, py, pw, ph, rad); ctx.fill();
  ctx.save();
  rr(px, py, pw, ph, rad); ctx.clip();
  ctx.fillStyle = '#b08a2e';
  ctx.fillRect(px, py, pw, 22);
  ctx.restore();
  ctx.lineWidth = 2;
  ctx.strokeStyle = '#ffe97a';
  rr(px + 0.5, py + 0.5, pw - 1, ph - 1, rad);
  ctx.stroke();
  ctx.fillStyle = '#1a1506';
  ctx.font = 'bold 10px monospace';
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.fillText('CONSTRUCTION #' + (mine.idx + 2), px + pw / 2, py + 11);

  const cElapsed = now - (mine.constructionStart || 0);
  const secLeft  = Math.max(0, Math.ceil((_CONSTRUCTION_MS - cElapsed) / 1000));
  const mm = Math.floor(secLeft / 60), ss = secLeft % 60;
  const timeStr = mm > 0 ? `${mm}:${String(ss).padStart(2,'0')}` : `${ss}s`;
  const prog = Math.min(1, cElapsed / _CONSTRUCTION_MS);

  ctx.textAlign = 'left'; ctx.textBaseline = 'middle';
  ctx.font = '10px monospace';
  ctx.fillStyle = '#cfcfcf';
  ctx.fillText('Time left:', px + 10, py + 38);
  ctx.fillStyle = '#ffe97a';
  ctx.textAlign = 'right';
  ctx.fillText(timeStr, px + pw - 10, py + 38);
  ctx.textAlign = 'left';
  ctx.fillStyle = '#cfcfcf';
  ctx.fillText('Progress:', px + 10, py + 54);
  ctx.fillStyle = '#ffe97a';
  ctx.textAlign = 'right';
  ctx.fillText(Math.round(prog * 100) + '%', px + pw - 10, py + 54);

  // Speed up mygtukas
  const bw2 = pw - 20, bh2 = 28;
  const bxU = px + 10;
  const byU = py + ph - bh2 - 10;
  const hoverBtn = _worldMx >= bxU && _worldMx <= bxU + bw2 && _worldMy >= byU && _worldMy <= byU + bh2;
  const canAfford = _ronkeBalance >= _SPEEDUP_COST;
  ctx.fillStyle = !canAfford ? '#3a3a3a' : (hoverBtn ? '#6ec56e' : '#4e9e4e');
  rr(bxU, byU, bw2, bh2, 5); ctx.fill();
  ctx.lineWidth = 1.5;
  ctx.strokeStyle = canAfford ? '#a8f0a8' : '#666';
  rr(bxU + 0.5, byU + 0.5, bw2 - 1, bh2 - 1, 5); ctx.stroke();
  ctx.fillStyle = canAfford ? '#fff' : '#999';
  ctx.font = 'bold 10px monospace';
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.lineWidth = 2; ctx.strokeStyle = 'rgba(0,0,0,0.45)';
  const label = 'SPEED UP 10\u00D7  \u26A1' + _SPEEDUP_COST;
  ctx.strokeText(label, bxU + bw2 / 2, byU + bh2 / 2 + 1);
  ctx.fillText(label, bxU + bw2 / 2, byU + bh2 / 2 + 1);

  // Close X
  const cxSz = 14;
  const cxX = px + pw - cxSz - 5;
  const cxY = py + 4;
  const hovX = _worldMx >= cxX && _worldMx <= cxX + cxSz && _worldMy >= cxY && _worldMy <= cxY + cxSz;
  ctx.fillStyle = hovX ? '#ff6e6e' : 'rgba(0,0,0,0.25)';
  rr(cxX, cxY, cxSz, cxSz, 3); ctx.fill();
  ctx.strokeStyle = '#fff';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(cxX + 4, cxY + 4); ctx.lineTo(cxX + cxSz - 4, cxY + cxSz - 4);
  ctx.moveTo(cxX + cxSz - 4, cxY + 4); ctx.lineTo(cxX + 4, cxY + cxSz - 4);
  ctx.stroke();
  ctx.restore();
  return { btn: { x: bxU, y: byU, w: bw2, h: bh2 }, close: { x: cxX, y: cxY, w: cxSz, h: cxSz } };
}

function _spawnCoinParticle(wx, wy) {
  _coinParticles.push({ wx: wx - 40, wy: wy - 95, born: performance.now() });
}
function _triggerBuildingSquish(name) {
  _buildingSquish = { name, start: performance.now() };
}
function _drawCoinParticles(now) {
  if (!_coinParticles.length) return;
  const DUR = 700;
  for (let i = _coinParticles.length - 1; i >= 0; i--) {
    const p = _coinParticles[i];
    const el = now - p.born;
    if (el > DUR) { _coinParticles.splice(i, 1); continue; }
    const prog  = el / DUR;
    const frame = Math.floor(el / (1000 / 8)) % 8;
    const alpha = prog > 0.5 ? 1 - (prog - 0.5) / 0.5 : 1;
    const sz    = 38;
    const thumb = _getRonkeCoinThumb(sz, frame);
    if (!thumb) continue;
    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.drawImage(thumb, p.wx - sz / 2, p.wy - 30 * prog);
    ctx.restore();
  }
}
