const _SHAM_PROJ_FRAMES = 3, _SHAM_PROJ_W = 128, _SHAM_PROJ_H = 128, _SHAM_PROJ_MS = 90;
const _SHAM_EXPL_FRAMES = 9, _SHAM_EXPL_W = 128, _SHAM_EXPL_H = 128, _SHAM_EXPL_MS = 55;
