const _towerAoeBlasts = []; // procedural ring+spark blast for tower AoE arrows
let _towerAoeCellSprite = null; // pre-rendered radial-fill sprite (avoids gradient rebuild per frame)
function _getTowerAoeCellSprite() {
  if (_towerAoeCellSprite) return _towerAoeCellSprite;
  const r = Math.max(8, Math.ceil(CELL * 0.6));
  const cv = document.createElement('canvas');
  cv.width = r * 2; cv.height = r * 2;
  const c = cv.getContext('2d');
  const g = c.createRadialGradient(r, r, 0, r, r, r);
  g.addColorStop(0, '#ffffff');
  g.addColorStop(0.45, 'rgba(255,244,210,0.85)');
  g.addColorStop(1, 'rgba(220,200,160,0)');
  c.fillStyle = g;
  c.fillRect(0, 0, r * 2, r * 2);
  _towerAoeCellSprite = { canvas: cv, r };
  return _towerAoeCellSprite;
}

function getShamanFrame(u, dir) {
  const isMoving = (typeof u._f9Moving === 'boolean')
    ? u._f9Moving
    : (Math.abs(u.rx - u.x) > 0.05 || Math.abs(u.ry - u.y) > 0.05);
  const swingElapsed = u.swingStart ? performance.now() - u.swingStart : Infinity;
  const swingDur = (10 / SHAMAN_ANIM_FPS.attack) * 1000;
  const isAttacking = swingElapsed < swingDur;

  let anim = 'idle';
  if (isAttacking) anim = 'attack';
  else if (isMoving) anim = 'run';

  const fps    = SHAMAN_ANIM_FPS[anim];
  const frames = shamanAnimFrames[anim][dir];
  if (!frames || frames.length === 0) return null;

  let idx;
  if (isAttacking) {
    idx = Math.min(Math.floor(swingElapsed / (1000 / fps)), frames.length - 1);
  } else {
    idx = Math.floor(performance.now() / (1000 / fps)) % frames.length;
  }
  return frames[idx];
}

// ===== HARPOON FISH (barracks unit) =====
// Naudoja jau užkrautus _fishAnims (idle=8f, run=6f, throw=8f, 192×192).
// swingStart/throwStart nustatoma action handler'yje, animacija paleidžia harpūną ~fire frame'e.
const _HFISH_FRAME_SZ = 192;
const _HFISH_THROW_FRAMES = 8, _HFISH_THROW_MS = 90;
const _HFISH_THROW_FIRE_FRAME = 5;
const _HFISH_IDLE_FRAMES = 8, _HFISH_IDLE_MS = 120;
const _HFISH_RUN_FRAMES = 6, _HFISH_RUN_MS = 110;
function getHarpoonFishFrameState(u) {
  const isMoving = (typeof u._f9Moving === 'boolean')
    ? u._f9Moving
    : (Math.abs(u.rx - u.x) > 0.05 || Math.abs(u.ry - u.y) > 0.05);
  const throwElapsed = u.hfishThrowStart ? performance.now() - u.hfishThrowStart : Infinity;
  const throwDur = _HFISH_THROW_FRAMES * _HFISH_THROW_MS;
  const isThrowing = throwElapsed < throwDur;
  let anim, frames, ms, sheet;
  if (isThrowing) {
    anim = 'throw'; frames = _HFISH_THROW_FRAMES; ms = _HFISH_THROW_MS; sheet = _fishAnims.throw.img;
  } else if (isMoving) {
    anim = 'run'; frames = _HFISH_RUN_FRAMES; ms = _HFISH_RUN_MS; sheet = _fishAnims.run.img;
  } else {
    anim = 'idle'; frames = _HFISH_IDLE_FRAMES; ms = _HFISH_IDLE_MS; sheet = _fishAnims.idle.img;
  }
  if (!sheet || !sheet.complete || !sheet.naturalWidth) return null;
  let idx;
  if (isThrowing) idx = Math.min(Math.floor(throwElapsed / ms), frames - 1);
  else idx = Math.floor(performance.now() / ms) % frames;
  return { sheet, sx: idx * _HFISH_FRAME_SZ, sy: 0, sw: _HFISH_FRAME_SZ, sh: _HFISH_FRAME_SZ };
}

// Archer unit frame state — naudoja _archerAnims (idle/run/shoot, 192px frame).
function getArcherUnitFrameState(u) {
  const FW = 192;
  const isMoving = (typeof u._f9Moving === 'boolean')
    ? u._f9Moving
    : (Math.abs(u.rx - u.x) > 0.05 || Math.abs(u.ry - u.y) > 0.05);
  const throwElapsed = u.hfishThrowStart ? performance.now() - u.hfishThrowStart : Infinity;
  const shootDur = _archerAnims.shoot.frames * _archerAnims.shoot.ms;
  const isShooting = throwElapsed < shootDur;
  let anim, sheet, frames, ms;
  if (isShooting)      { anim = _archerAnims.shoot; }
  else if (isMoving)   { anim = _archerAnims.run; }
  else                 { anim = _archerAnims.idle; }
  sheet = anim.img; frames = anim.frames; ms = anim.ms;
  if (!sheet || !sheet.complete || !sheet.naturalWidth) return null;
  let idx;
  if (isShooting) idx = Math.min(Math.floor(throwElapsed / ms), frames - 1);
  else idx = Math.floor(performance.now() / ms) % frames;
  return { sheet, sx: idx * FW, sy: 0, sw: FW, sh: FW };
}

function loadHorizontalSheetFrames(path, frameCount) {
  const sheet = new Image();
  // Mobile tinkle dalis image užklausų nutrūksta, o Image NIEKADA nebanto iš naujo →
  // unitai likdavo „raudonais taškais" amžinai. Retry iki 3× su backoff (2026-06-12).
  let _tries = 0;
  sheet.onerror = () => {
    if (_tries >= 3) return;
    _tries++;
    setTimeout(() => {
      sheet.src = path + (path.indexOf('?') >= 0 ? '&' : '?') + 'retry=' + _tries;
    }, 700 * _tries);
  };
  sheet.src = path;
  const frames = [];
  for (let i = 0; i < frameCount; i++) {
    const frame = new Image();
    frame.src = path;
    frames.push(frame);
  }
  return { sheet, frames, frameCount };
}

