// Phase 15 — fetch live mint cost from contract (RPC), update pricing strip + curve.
// Post-mainnet-flip (2026-05-23): RPC + contract now point to Ronin Mainnet.
async function _refreshTrophyPricing() {
  const RONIN_RPC = 'https://api.roninchain.com/rpc';
  const CONTRACT = (window.Wallet && window.Wallet.TROPHY_CONTRACT) || '0xb7873833e7AC43c921AF736F2E3988Ba26a39512';
  // Function selectors:
  const SELECTORS = {
    getCurrentMintPrice: '0xe82ded21',  // getCurrentMintPrice() -> uint256
    currentBatch:        '0x76cd940e',  // currentBatch() -> uint256
    remainingInBatch:    '0xcbecc4ab',  // remainingInBatch() -> uint256
    totalSupply:         '0x18160ddd',  // totalSupply() -> uint256
  };
  // Retry — public Ronin RPC rate-limit'ina (ypač burst'ą). 3 bandymai su backoff;
  // grąžinam null tik jei tikrai nepavyko (NE 0 — kad neperrašytų į „0 / 10,000").
  async function rpcCall(selector, tries) {
    tries = tries || 3;
    for (let i = 0; i < tries; i++) {
      try {
        const resp = await fetch(RONIN_RPC, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            jsonrpc: '2.0', method: 'eth_call', id: 1,
            params: [{ to: CONTRACT, data: selector }, 'latest'],
          }),
        });
        if (resp.ok) {
          const j = await resp.json();
          if (j && typeof j.result === 'string') {
            if (j.result === '0x') return 0n;
            try { return BigInt(j.result); } catch (_) { return 0n; }
          }
        }
      } catch (_) {}
      // rate-limit / klaida → palaukiam ir bandom dar
      await new Promise((r) => setTimeout(r, 450 * (i + 1)));
    }
    return null;   // visi bandymai krito
  }
  try {
    // Sekvenciškai (NE 4 iškart) — kad nesukeltų burst rate-limit'o.
    const priceWei  = await rpcCall(SELECTORS.getCurrentMintPrice);
    const batch     = await rpcCall(SELECTORS.currentBatch);
    const remaining = await rpcCall(SELECTORS.remainingInBatch);
    const supply    = await rpcCall(SELECTORS.totalSupply);
    // null = RPC nepavyko → NEperrašom (paliekam esamą / „…"), kad nerodytų klaidingo 0.
    const priceRon = (priceWei == null) ? null : Number(priceWei) / 1e18;
    const batchNum = (batch == null) ? null : Number(batch);
    const rem = (remaining == null) ? null : Number(remaining);
    const totalSupply = (supply == null) ? null : Number(supply);
    // Card 1: current cost
    const nowEl = document.getElementById('trophy-pricing-now');
    if (nowEl && priceRon !== null) nowEl.innerHTML = priceRon === 0 ? 'FREE' : (priceRon + ' <em style="font-size:10px;color:#d49a2a;font-style:normal;">RON</em>');
    // Card 2: minted so far
    const batchEl = document.getElementById('trophy-pricing-batch');
    if (batchEl && totalSupply !== null) batchEl.innerHTML = totalSupply.toLocaleString() + ' <em style="font-size:10px;color:#7a9aa6;font-style:normal;">/ 10,000</em>';
    const batchSubEl = document.getElementById('trophy-pricing-batchsub');
    if (batchSubEl && batchNum !== null) batchSubEl.textContent = `batch ${batchNum + 1}/10`;
    // Card 3: next jump (tik jei batch+remaining užsikrovė)
    const NEXT_PRICES = [1, 2, 3, 4, 6, 8, 10, 12, 15, null];
    const nextEl = document.getElementById('trophy-pricing-next');
    const nextSubEl = document.getElementById('trophy-pricing-nextsub');
    if (nextEl && nextSubEl && batchNum !== null) {
      const nextPrice = NEXT_PRICES[batchNum];
      if (nextPrice === null) {
        nextEl.textContent = '—';
        nextSubEl.textContent = 'Final batch (sold out next)';
      } else {
        nextEl.innerHTML = nextPrice + ' <em style="font-size:10px;color:#d49a2a;font-style:normal;">RON</em>';
        if (rem !== null) nextSubEl.textContent = `After ${rem.toLocaleString()} more mints`;
      }
    }
    // Stash for claim modal too (tik jei užsikrovė)
    if (priceRon !== null) window._trophyCurrentPriceRon = priceRon;
    if (batchNum !== null) window._trophyCurrentBatch = batchNum;
  } catch (e) {
    console.warn('[trophy pricing fetch]', e);
  }
}
window._refreshTrophyPricing = _refreshTrophyPricing;
window.closeTrophyPanel = function closeTrophyPanel() {
  document.getElementById('trophy-overlay').classList.remove('active');
  if (_trophyPanelRefreshTimer) {
    clearInterval(_trophyPanelRefreshTimer);
    _trophyPanelRefreshTimer = null;
  }
};

// ── SEC-6: Optimistic UI training gate ─────────────────────────────────
// Start production IMMEDIATELY (zero perceived lag). Server validates in
// background via register-training. If server rejects (insufficient or
// rate-limit), rollback: cancel production via onRollback + refund.
// Wallet-connected → server is source of truth on balance.
// Anonymous / server unavailable → pure local path.
function _f10TryStartTraining(utype, qty, localCost, onSuccess, onInsufficient, onRollback) {
  // 1. Local balance sanity check (fast)
  if (typeof _ronkeBalance !== 'number' || _ronkeBalance < localCost) {
    if (onInsufficient) onInsufficient();
    return;
  }
  // 2. Deduct + start IMMEDIATELY (optimistic)
  _ronkeBalance -= localCost;
  if (typeof window.updateRonkeBadge === 'function') window.updateRonkeBadge();
  if (typeof saveProfile === 'function') saveProfile();
  onSuccess();
  // OFFLINE: onSuccess gali nustatyti _barracksProductions (treniravimas) — dar kartą
  // persistuojam, kad startWall išliktų jei žaidėjas iškart perkrauna.
  if (typeof saveProfile === 'function') saveProfile();

  // 3. Background server validation (if wallet connected)
  const W = window.Wallet;
  const connected = !!(W && W.isConnected && W.isConnected());
  if (!connected || !window.SupabaseSync || typeof window.SupabaseSync.invoke !== 'function') return;
  const addr = W.getAddress && W.getAddress();
  if (!addr) return;

  (async () => {
    try {
      const resp = await window.SupabaseSync.invoke('register-training', {
        wallet: addr.toLowerCase(), utype, qty: qty || 1,
      });
      if (resp && resp.status === 404) return;   // edge fn missing → local-only
      if (!resp || !resp.ok || !resp.data || resp.data.ok !== true) {
        // ── SERVER REJECTED → ROLLBACK ──
        const err = (resp && resp.data && resp.data.error) || 'unknown';
        if (typeof logEvent === 'function') logEvent(`✗ Training rolled back: ${err}`, 'warn');
        _ronkeBalance += localCost;
        if (typeof window.updateRonkeBadge === 'function') window.updateRonkeBadge();
        if (typeof saveProfile === 'function') saveProfile();
        if (typeof onRollback === 'function') onRollback();
        return;
      }
      // Server confirmed → sync to server-authoritative balance.
      const serverBal = Number(resp.data.balance);
      if (Number.isFinite(serverBal)) {
        _ronkeBalance = serverBal;
        if (typeof window.updateRonkeBadge === 'function') window.updateRonkeBadge();
        if (typeof saveProfile === 'function') saveProfile();
      }
    } catch (e) {
      console.warn('[register-training] exception:', e);
    }
  })();
}

// ── F12 Pay-per-play pricing (MVP — localStorage, display only) ─────
// Base cost 10 RONKE × 2 augimas kiekvienam žaidimui per 24h.
// NFT holder discount: ÷N kur N = 1 (no NFT) / 3 (1+) / 3.5 (5+) / 4.5 (10+).
// First play per 24h = NEMOKAMAS. Reset = 24h po seniausio play log entry.
const _F12_PLAY_LOG_KEY = '_f12_plays_24h_log';
const _F12_BASE_COST = 10;
const _F12_GROWTH = 2;
const _F12_FIRST_FREE = true;

function _f12NftDiscountDivisor() {
  const W = window.Wallet;
  if (!W || !W.getEligibleNftCountCached) return 1;
  const elig = W.getEligibleNftCountCached();
  if (elig >= 10) return 4.5;
  if (elig >= 5) return 3.5;
  if (elig >= 1) return 3.0;
  return 1.0;
}
function _f12GetPlaysIn24h() {
  let raw = [];
  try { raw = JSON.parse(localStorage.getItem(_F12_PLAY_LOG_KEY) || '[]'); } catch (_) {}
  if (!Array.isArray(raw)) raw = [];
  const cutoff = Date.now() - 24 * 60 * 60 * 1000;
  return raw.filter(t => typeof t === 'number' && t > cutoff);
}
function _f12CostForPlayN(playN /* 1-indexed */, divisor) {
  if (_F12_FIRST_FREE && playN === 1) return 0;
  const raw = _F12_BASE_COST * Math.pow(_F12_GROWTH, _F12_FIRST_FREE ? (playN - 2) : (playN - 1));
  return Math.ceil(raw / (divisor || 1));
}
function _f12LogPlay() {
  const plays = _f12GetPlaysIn24h();
  plays.push(Date.now());
  try { localStorage.setItem(_F12_PLAY_LOG_KEY, JSON.stringify(plays)); } catch (_) {}
}
function _f12HoursUntilReset(plays) {
  if (!plays.length) return 0;
  const oldest = Math.min.apply(null, plays);
  const expiresAt = oldest + 24 * 60 * 60 * 1000;
  return Math.max(0, (expiresAt - Date.now()) / (60 * 60 * 1000));
}
// FREE_PLAY_TESTING — kol testuojam pre-deck modal'ą + NFT integration. Reset to false prieš prod release.
window._F12_FREE_PLAY_TESTING = true;
window._f12CurrentCost = function() {
  const plays = _f12GetPlaysIn24h();
  const divisor = _f12NftDiscountDivisor();
  const nextPlayN = plays.length + 1;
  let cost = _f12CostForPlayN(nextPlayN, divisor);
  let costNoNft = _f12CostForPlayN(nextPlayN, 1);
  let afterCost = _f12CostForPlayN(nextPlayN + 1, divisor);
  if (window._F12_FREE_PLAY_TESTING) {
    cost = 0;
    costNoNft = 0;
    afterCost = 0;
  }
  return {
    playsToday: plays.length,
    nextPlayN,
    cost, costNoNft, afterCost,
    divisor,
    isHolder: divisor > 1,
    eligibleNftCount: (window.Wallet && window.Wallet.getEligibleNftCountCached) ? window.Wallet.getEligibleNftCountCached() : 0,
    resetInHours: _f12HoursUntilReset(plays),
  };
};

// ── F12 Entry Popup wrap ────────────────────────────────────────────
let _f12_realGotoF12 = null;
let _f12_pendingProceed = null;

// ── ON-CHAIN PLAY FEE — žaidėjas pasirašo 5 RONKE → treasury PRIEŠ žaidimą (PoD + vertė) ──
// Įjungta → pakeičia off-chain pay-per-play popup'ą. SIMULATE=true → lokalus testas be realaus TX.
window._F12_PAYTOPLAY = true;
window._F12_PAYTOPLAY_SIMULATE = false;     // testui be wallet/spend: nustatyk true
window._f12FeePaidForEntry = false;         // VIENAS 5 RONKE mokestis per battle įėjimą (reset _activateNow metu)
window._f12PayInFlight = false;
// Bendras play-fee mokėtojas — DALIJASI game.js gate + NFT Barracks START. Grąžina Promise.
// Mokama TIK 1× per įėjimą (flag), kad ir per PLAY, ir per Barracks START suveiktų BE dublio,
// ir VISADA prieš deck/BurnAuth parašą.
window._f12PayPlayFee = function () {
  return new Promise(function (resolve, reject) {
    if (!window._F12_PAYTOPLAY) { resolve(true); return; }
    if (window._f12FeePaidForEntry) { resolve(true); return; }                 // jau sumokėta šiam įėjimui
    if (window._F12_PAYTOPLAY_SIMULATE) { window._f12FeePaidForEntry = true; resolve(true); return; }
    if (!(window.Wallet && window.Wallet.payToPlay)) { reject(new Error('Wallet required')); return; }
    if (window._f12PayInFlight) { reject(new Error('Payment in progress')); return; }
    window._f12PayInFlight = true;
    if (typeof showGameNotification === 'function') showGameNotification('CONFIRM PLAY FEE', 'Sign 5 RONKE in your wallet', '#ffcf5c');
    window.Wallet.payToPlay().then(function () {
      window._f12PayInFlight = false; window._f12FeePaidForEntry = true; resolve(true);
    }).catch(function (e) { window._f12PayInFlight = false; reject(e); });
  });
};
function _f12PayToPlayThenProceed(onConfirm) {
  const go = function () {
    if (typeof onConfirm === 'function') { try { onConfirm(); } catch (e) { console.error('[F12 pay] proceed err', e); } }
    else if (typeof _f12_realGotoF12 === 'function') _f12_realGotoF12();
  };
  window._f12PayPlayFee().then(go).catch(function (e) {
    const msg = String((e && e.message) || e);
    if (typeof showGameNotification === 'function') showGameNotification('PLAY FEE', /reject|denied|cancel/i.test(msg) ? 'Cancelled' : (/session|expired|reconnect/i.test(msg) ? 'Session expired — refresh & reconnect' : (/wallet/i.test(msg) ? 'Connect wallet' : (/network|chain/i.test(msg) ? 'Wrong network' : 'Failed'))), '#e85d5d');
  });
}
function _f12TierLabel(divisor) {
  if (divisor >= 4.5) return 'TIER 3 · 10+ NFT';
  if (divisor >= 3.5) return 'TIER 2 · 5+ NFT';
  if (divisor >= 3.0) return 'TIER 1 · 1+ NFT';
  return 'NO TIER';
}

// Render YOUR NFT BONUSES card — computes & shows each bonus with real values.
function _renderF12BonusesCard(d) {
  const card = document.getElementById('f12e-bonuses');
  const iconEl = document.getElementById('f12e-bonus-icon');
  const titleEl = document.getElementById('f12e-bonus-title');
  const metaEl = document.getElementById('f12e-bonus-meta');
  const listEl = document.getElementById('f12e-bonus-list');
  if (!card || !listEl) return;

  card.classList.remove('is-active', 'is-no-nft', 'is-pending');
  listEl.innerHTML = '';

  const W = window.Wallet;
  const connected = !!(W && W.isConnected && W.isConnected());
  if (!connected) {
    card.classList.add('is-no-nft');
    if (iconEl) iconEl.textContent = '🔌';
    if (titleEl) titleEl.textContent = 'WALLET NOT CONNECTED';
    if (metaEl) metaEl.textContent = '';
    listEl.innerHTML = '<div class="f12e-bonus-empty">Connect your Ronin wallet to see NFT bonuses</div>';
    return;
  }

  const totalNft = (W.getRonkeNFTCount && W.getRonkeNFTCount()) || 0;
  const eligNft = (W.getEligibleNftCountCached && W.getEligibleNftCountCached()) || 0;

  // ── State: NO NFT AT ALL ──
  if (totalNft === 0) {
    card.classList.add('is-no-nft');
    if (iconEl) iconEl.textContent = '◇';
    if (titleEl) titleEl.textContent = 'NO ACTIVE BONUSES';
    if (metaEl) metaEl.textContent = '0 NFT';
    listEl.innerHTML = `
      <div class="f12e-bonus-empty">
        Get RONKE NFT to unlock all bonuses below.<br>
        <a href="https://marketplace.skymavis.com/collections/ronkeverse" target="_blank">Marketplace →</a>
      </div>`;
    _renderF12BonusList(listEl, 0, 0, /*previewMode=*/true);
    return;
  }

  // ── State: HAS NFT BUT NOT ELIGIBLE YET (24h hold pending) ──
  if (eligNft === 0) {
    card.classList.add('is-pending');
    if (iconEl) iconEl.textContent = '⏰';
    if (titleEl) titleEl.textContent = 'BONUSES PENDING';
    if (metaEl) metaEl.textContent = totalNft + ' NFT · 0 eligible';
    listEl.innerHTML = `
      <div class="f12e-bonus-empty">
        24h hold rule active. Bonuses unlock automatically once any NFT in your wallet completes 24h hold.
      </div>`;
    _renderF12BonusList(listEl, totalNft, 0, /*previewMode=*/true);
    return;
  }

  // ── State: ACTIVE BONUSES ──
  card.classList.add('is-active');
  if (iconEl) iconEl.textContent = '★';
  if (titleEl) titleEl.textContent = 'YOUR ACTIVE BONUSES';
  if (metaEl) metaEl.textContent = totalNft + ' NFT · ' + eligNft + ' eligible';
  _renderF12BonusList(listEl, totalNft, eligNft, /*previewMode=*/false);
}
function _renderF12BonusList(listEl, totalNft, eligNft, previewMode) {
  const isActive = !previewMode && eligNft >= 1;
  // Mining: +2% per eligible NFT, cap +10%
  const miningBoost = Math.min(eligNft * 0.02, 0.10);
  const miningPct = Math.round((0.5 + miningBoost) * 100);
  // Play discount divisor
  let playDiv = 1;
  if (eligNft >= 10) playDiv = 4.5;
  else if (eligNft >= 5) playDiv = 3.5;
  else if (eligNft >= 1) playDiv = 3.0;

  const rows = [
    {
      icon: '🏰',
      name: 'Build / train speed',
      detail: isActive
        ? '60s &rarr; <strong>30s</strong> (2&times; faster)'
        : '1&times; (60s per build / train)',
      previewDetail: '2&times; faster (60s &rarr; 30s)',
      active: isActive,
    },
    {
      icon: '⛏',
      name: 'RONKE drop chance',
      detail: isActive
        ? `50% &rarr; <strong>${miningPct}%</strong> (+${Math.round(miningBoost*100)}%)`
        : 'Base 50% drop rate',
      previewDetail: '+2% per NFT, cap +10% (5+ NFT)',
      active: isActive,
    },
    {
      icon: '🎯',
      name: 'F12 score multiplier',
      detail: isActive
        ? '&times;1.0 &rarr; <strong>&times;1.5</strong> (+50%)'
        : '&times;1.0 (base scoring)',
      previewDetail: '&times;1.5 score multiplier',
      active: isActive,
    },
    {
      icon: '🪙',
      name: 'Pay-per-play discount',
      detail: isActive
        ? `Cost &divide; <strong>${playDiv}</strong> cheaper`
        : 'Full pay-per-play price',
      previewDetail: '&divide;3 (1+), &divide;3.5 (5+), &divide;4.5 (10+)',
      active: isActive,
    },
  ];

  for (const r of rows) {
    const div = document.createElement('div');
    div.className = 'f12e-bonus-row ' + (r.active ? 'is-active' : 'is-inactive');
    div.innerHTML = `
      <div class="f12e-bonus-icon">${r.icon}</div>
      <div class="f12e-bonus-text">
        <div class="f12e-bonus-name">${r.name}</div>
        <div class="f12e-bonus-detail">${previewMode ? r.previewDetail : r.detail}</div>
      </div>
      <span class="f12e-bonus-tag">${r.active ? 'ACTIVE' : (previewMode ? 'LOCKED' : 'OFF')}</span>
    `;
    listEl.appendChild(div);
  }
}
function _showF12EntryPopup(onConfirm) {
  // PLAY FEE imamas TIK NFT Barracks START metu (tik NFT mūšiui). FREE play — BE mokesčio.
  // Tad čia (įėjimas/PLAY) nieko neimam — tiesiog praleidžiam į picker'į.
  if (window._F12_PAYTOPLAY) {
    if (typeof onConfirm === 'function') { try { onConfirm(); } catch (e) { console.error('[F12] proceed err', e); } }
    else if (typeof _f12_realGotoF12 === 'function') _f12_realGotoF12();
    return;
  }
  // FREE_PLAY_TESTING: visiškai praleidžiam entry popup'ą — testuojam be RONKE check'ų
  if (window._F12_FREE_PLAY_TESTING) {
    if (typeof onConfirm === 'function') {
      try { onConfirm(); } catch (e) { console.error('[F12 free play] proceed err', e); }
    } else if (typeof _f12_realGotoF12 === 'function') {
      _f12_realGotoF12();
    }
    return;
  }
  _f12_pendingProceed = onConfirm || null;
  const d = window._f12CurrentCost();

  // ── HERO ──
  const valEl = document.getElementById('f12e-cost-value');
  const subEl = document.getElementById('f12e-cost-sub');
  if (valEl) {
    valEl.textContent = d.cost === 0 ? 'FREE' : (d.cost + ' RONKE');
    valEl.classList.toggle('is-free', d.cost === 0);
  }
  if (subEl) {
    if (d.playsToday === 0) subEl.textContent = 'First play of 24h cycle';
    else subEl.textContent = `Play #${d.nextPlayN} in current 24h cycle`;
  }

  // ── Affordability check + hero button state ──
  const balance = (typeof _ronkeBalance === 'number') ? _ronkeBalance : 0;
  const insufficient = d.cost > 0 && balance < d.cost;
  const heroBtn = document.getElementById('f12e-hero-btn');
  if (heroBtn) {
    heroBtn.classList.toggle('is-insufficient-state', insufficient);
  }
  const subEl2 = document.getElementById('f12e-cost-sub');
  if (subEl2 && insufficient) {
    subEl2.innerHTML = `⚠ Insufficient — you have ${Math.floor(balance)} RONKE`;
  }

  // ── HEADER subtitle (NFT count status) ──
  const subtEl = document.getElementById('f12e-subtitle');
  if (subtEl) {
    const W = window.Wallet;
    if (!W || !W.isConnected || !W.isConnected()) {
      subtEl.textContent = 'Pay-per-play entry · wallet not connected';
    } else {
      const total = (W.getRonkeNFTCount && W.getRonkeNFTCount()) || 0;
      const elig = (W.getEligibleNftCountCached && W.getEligibleNftCountCached()) || 0;
      if (total === 0) subtEl.textContent = 'Pay-per-play entry · 0 NFT';
      else if (elig === 0) subtEl.textContent = `Pay-per-play entry · ${total} NFT (24h hold pending)`;
      else subtEl.textContent = `Pay-per-play entry · ${total} NFT · ${elig} eligible`;
    }
  }

  // ── DISCOUNT card (always visible) ──
  // - Holder: shows actual discount vs no-NFT baseline.
  // - Non-holder: shows "If you had 1 NFT" preview with marketplace CTA.
  const discEl = document.getElementById('f12e-discount');
  if (discEl) {
    discEl.style.display = 'block';
    const noNftLbl = document.getElementById('f12e-cost-noNft');
    const withNftLbl = document.getElementById('f12e-cost-withNft');
    const nftCnt = document.getElementById('f12e-nft-count');
    const tierBadge = document.getElementById('f12e-tier-badge');
    const saveLbl = document.getElementById('f12e-disc-save');
    const iconEl = document.getElementById('f12e-disc-icon');
    const titleEl = document.getElementById('f12e-disc-title');
    const lblLeft = document.getElementById('f12e-disc-lbl-left');
    const lblRight = document.getElementById('f12e-disc-lbl-right');

    if (d.isHolder && d.cost !== d.costNoNft) {
      // ── Holder mode ──
      discEl.classList.remove('is-preview');
      discEl.classList.add('is-active');
      if (iconEl) iconEl.textContent = '★';
      if (titleEl) titleEl.textContent = 'NFT HOLDER DISCOUNT';
      if (tierBadge) {
        tierBadge.textContent = _f12TierLabel(d.divisor);
        tierBadge.style.display = '';
      }
      if (lblLeft) lblLeft.textContent = 'Without NFT';
      if (lblRight) lblRight.innerHTML = `Your cost (<span id="f12e-nft-count">${d.eligibleNftCount}</span> NFT)`;
      if (noNftLbl) noNftLbl.textContent = d.costNoNft === 0 ? 'FREE' : (d.costNoNft + ' RONKE');
      if (withNftLbl) withNftLbl.textContent = d.cost === 0 ? 'FREE' : (d.cost + ' RONKE');
      if (saveLbl) saveLbl.innerHTML = '&divide;' + d.divisor + ' cheaper for holders';
    } else {
      // ── Non-holder / pending mode: "If you had 1 NFT" preview ──
      discEl.classList.remove('is-active');
      discEl.classList.add('is-preview');
      const previewDivisor = 3.0;  // 1+ NFT tier
      const previewCost = _f12CostForPlayN(d.nextPlayN, previewDivisor);
      const savings = d.costNoNft - previewCost;
      if (iconEl) iconEl.textContent = '👀';
      if (titleEl) titleEl.textContent = 'IF YOU HAD 1 NFT';
      if (tierBadge) {
        tierBadge.textContent = 'PREVIEW';
        tierBadge.style.display = '';
      }
      if (lblLeft) lblLeft.textContent = 'You pay';
      if (lblRight) lblRight.innerHTML = 'With 1 NFT';
      if (noNftLbl) noNftLbl.textContent = d.costNoNft === 0 ? 'FREE' : (d.costNoNft + ' RONKE');
      if (withNftLbl) withNftLbl.textContent = previewCost === 0 ? 'FREE' : (previewCost + ' RONKE');
      if (saveLbl) {
        if (savings > 0) {
          saveLbl.innerHTML = `Save ${savings} RONKE &middot; <a href="https://marketplace.skymavis.com/collections/ronkeverse" target="_blank">Get NFT &rarr;</a>`;
        } else {
          saveLbl.innerHTML = '<a href="https://marketplace.skymavis.com/collections/ronkeverse" target="_blank">Get RONKE NFT &rarr;</a> to unlock bonuses';
        }
      }
    }
  }

  // ── SCHEDULE grid ──
  const schedEl = document.getElementById('f12e-schedule');
  if (schedEl) {
    schedEl.innerHTML = '';
    const totalToShow = 6;
    for (let i = 1; i <= totalToShow; i++) {
      const cost = _f12CostForPlayN(i, d.divisor);
      const item = document.createElement('div');
      item.className = 'f12e-sched-item';
      if (i < d.nextPlayN) item.classList.add('is-past');
      if (i === d.nextPlayN) item.classList.add('is-current');
      const costStr = cost === 0 ? 'FREE' : (cost + ' RONKE');
      const costClass = cost === 0 ? 'is-free' : '';
      item.innerHTML = `<span class="f12e-sched-num">Play #${i}</span><span class="f12e-sched-cost ${costClass}">${costStr}</span>`;
      schedEl.appendChild(item);
    }
  }

  // ── RESET timer ──
  const resetEl = document.getElementById('f12e-reset');
  const resetH = document.getElementById('f12e-reset-h');
  if (resetEl) {
    if (d.playsToday > 0) {
      resetEl.style.display = 'block';
      if (resetH) resetH.textContent = '~' + Math.ceil(d.resetInHours) + 'h';
    } else {
      resetEl.style.display = 'none';
    }
  }

  // ── BALANCE BAR ──
  const balRound = Math.floor(balance);
  const after = balRound - d.cost;
  const bar = document.getElementById('f12e-balance-bar');
  const nowEl = document.getElementById('f12e-bal-now');
  const afterEl = document.getElementById('f12e-bal-after');
  const afterLbl = document.getElementById('f12e-bal-after-lbl');
  if (nowEl) nowEl.textContent = balRound;
  if (afterEl) afterEl.textContent = insufficient ? balRound : after;
  if (afterLbl) afterLbl.textContent = d.cost === 0 ? 'NO CHARGE' : (insufficient ? 'NEED ' + (d.cost - balRound) : 'AFTER PLAY');
  if (bar) {
    bar.classList.toggle('is-bad', insufficient);
    bar.classList.remove('is-denying');
  }

  const ov = document.getElementById('f12-entry-overlay');
  if (ov) ov.classList.add('active');
  SFX.play(700, 0.08, 0.05, 'square', 300);

  // ── SEC-5: refresh cost from server (authoritative source) ──
  // Local estimate renders immediately; server reply updates within ~500ms.
  // If user plays on multiple devices, server has the true counter.
  _f12FetchServerCostAndUpdate();
}

// Fetch server-side cost via get-play-cost edge fn. Updates DOM if popup
// is still open. Silently no-ops on failure / no wallet.
async function _f12FetchServerCostAndUpdate() {
  try {
    const W = window.Wallet;
    if (!W || !W.isConnected || !W.isConnected()) return;
    if (!window.SupabaseSync || typeof window.SupabaseSync.invoke !== 'function') return;
    const addr = W.getAddress && W.getAddress();
    if (!addr) return;
    const resp = await window.SupabaseSync.invoke('get-play-cost', { wallet: addr.toLowerCase() });
    const data = resp && resp.data;
    if (!resp || !resp.ok || !data || data.ok !== true) return;
    // Bail if popup closed during fetch
    const ov = document.getElementById('f12-entry-overlay');
    if (!ov || !ov.classList.contains('active')) return;

    const cost = Number(data.cost) || 0;
    const costNoNft = Number(data.costNoNft) || 0;
    const balance = Number(data.balance) || 0;
    const nextPlayN = Number(data.nextPlayN) || 1;
    const playsToday = Number(data.playsToday) || 0;
    const divisor = Number(data.divisor) || 1;
    const eligibleNftCount = Number(data.eligibleNftCount) || 0;
    const afterCost = Number(data.afterCost) || 0;
    const insufficient = cost > 0 && balance < cost;

    // Update hero cost
    const valEl = document.getElementById('f12e-cost-value');
    if (valEl) {
      valEl.textContent = cost === 0 ? 'FREE' : (cost + ' RONKE');
      valEl.classList.toggle('is-free', cost === 0);
    }
    const subEl = document.getElementById('f12e-cost-sub');
    if (subEl) {
      if (insufficient) subEl.innerHTML = `⚠ Insufficient — you have ${balance} RONKE`;
      else if (playsToday === 0) subEl.textContent = 'First play of 24h cycle (server-verified)';
      else subEl.textContent = `Play #${nextPlayN} in current 24h cycle (server-verified)`;
    }
    // Update balance bar
    const nowEl = document.getElementById('f12e-bal-now');
    const afterEl = document.getElementById('f12e-bal-after');
    const afterLbl = document.getElementById('f12e-bal-after-lbl');
    const bar = document.getElementById('f12e-balance-bar');
    if (nowEl) nowEl.textContent = balance;
    if (afterEl) afterEl.textContent = insufficient ? balance : (balance - cost);
    if (afterLbl) afterLbl.textContent = cost === 0 ? 'NO CHARGE' : (insufficient ? 'NEED ' + (cost - balance) : 'AFTER PLAY');
    if (bar) bar.classList.toggle('is-bad', insufficient);
    // Update hero state
    const heroBtn = document.getElementById('f12e-hero-btn');
    if (heroBtn) heroBtn.classList.toggle('is-insufficient-state', insufficient);

    // Update DISCOUNT card with server's nextPlayN — preview was rendered
    // with local nextPlayN=1 (FREE first play), making "If you had 1 NFT"
    // wrongly show FREE→FREE when server is actually on play #2+.
    const discEl = document.getElementById('f12e-discount');
    if (discEl) {
      const isHolder = divisor > 1;
      const previewDivisor = 3.0;
      const previewCost = _f12CostForPlayN(nextPlayN, previewDivisor);
      const tierBadge = document.getElementById('f12e-tier-badge');
      const iconEl = document.getElementById('f12e-disc-icon');
      const titleEl = document.getElementById('f12e-disc-title');
      const lblLeft = document.getElementById('f12e-disc-lbl-left');
      const lblRight = document.getElementById('f12e-disc-lbl-right');
      const noNftLbl = document.getElementById('f12e-cost-noNft');
      const withNftLbl = document.getElementById('f12e-cost-withNft');
      const saveLbl = document.getElementById('f12e-disc-save');

      if (isHolder && cost !== costNoNft) {
        discEl.classList.remove('is-preview');
        discEl.classList.add('is-active');
        if (iconEl) iconEl.textContent = '★';
        if (titleEl) titleEl.textContent = 'NFT HOLDER DISCOUNT';
        if (tierBadge) tierBadge.textContent = (divisor >= 4.5 ? 'TIER 3 · 10+ NFT' : divisor >= 3.5 ? 'TIER 2 · 5+ NFT' : 'TIER 1 · 1+ NFT');
        if (lblLeft) lblLeft.textContent = 'Without NFT';
        if (lblRight) lblRight.innerHTML = `Your cost (<span>${eligibleNftCount}</span> NFT)`;
        if (noNftLbl) noNftLbl.textContent = costNoNft === 0 ? 'FREE' : (costNoNft + ' RONKE');
        if (withNftLbl) withNftLbl.textContent = cost === 0 ? 'FREE' : (cost + ' RONKE');
        if (saveLbl) saveLbl.innerHTML = '&divide;' + divisor + ' cheaper for holders';
      } else {
        // Non-holder preview: "If you had 1 NFT"
        const savings = costNoNft - previewCost;
        discEl.classList.remove('is-active');
        discEl.classList.add('is-preview');
        if (iconEl) iconEl.textContent = '👀';
        if (titleEl) titleEl.textContent = 'IF YOU HAD 1 NFT';
        if (tierBadge) tierBadge.textContent = 'PREVIEW';
        if (lblLeft) lblLeft.textContent = 'You pay';
        if (lblRight) lblRight.innerHTML = 'With 1 NFT';
        if (noNftLbl) noNftLbl.textContent = costNoNft === 0 ? 'FREE' : (costNoNft + ' RONKE');
        if (withNftLbl) withNftLbl.textContent = previewCost === 0 ? 'FREE' : (previewCost + ' RONKE');
        if (saveLbl) {
          if (savings > 0) {
            saveLbl.innerHTML = `Save ${savings} RONKE &middot; <a href="https://marketplace.skymavis.com/collections/ronkeverse" target="_blank">Get NFT &rarr;</a>`;
          } else {
            saveLbl.innerHTML = '<a href="https://marketplace.skymavis.com/collections/ronkeverse" target="_blank">Get RONKE NFT &rarr;</a> to unlock bonuses';
          }
        }
      }
    }

    // Update pricing schedule grid to match server's nextPlayN (fixes
    // inconsistency where localStorage has plays the server doesn't yet,
    // e.g. legacy plays from before SEC-5 deploy).
    const schedEl = document.getElementById('f12e-schedule');
    if (schedEl) {
      schedEl.innerHTML = '';
      const totalToShow = 6;
      for (let i = 1; i <= totalToShow; i++) {
        const c = _f12CostForPlayN(i, divisor);
        const item = document.createElement('div');
        item.className = 'f12e-sched-item';
        if (i < nextPlayN) item.classList.add('is-past');
        if (i === nextPlayN) item.classList.add('is-current');
        const costStr = c === 0 ? 'FREE' : (c + ' RONKE');
        const costClass = c === 0 ? 'is-free' : '';
        item.innerHTML = `<span class="f12e-sched-num">Play #${i}</span><span class="f12e-sched-cost ${costClass}">${costStr}</span>`;
        schedEl.appendChild(item);
      }
    }

    // Update next-cost preview
    const nextEl = document.getElementById('f12e-next-cost');
    if (nextEl) nextEl.textContent = afterCost === 0 ? 'FREE' : (afterCost + ' RONKE');

    // Sync localStorage play log with server count (so local fallback uses
    // realistic baseline when offline).
    try {
      const existing = _f12GetPlaysIn24h();
      if (existing.length !== playsToday) {
        // Rebuild log: keep server-authoritative count, timestamp them in past
        const now = Date.now();
        const rebuilt = [];
        for (let i = 0; i < playsToday; i++) {
          rebuilt.push(now - (playsToday - i) * 60000);   // stagger 1min apart, retroactively
        }
        localStorage.setItem(_F12_PLAY_LOG_KEY, JSON.stringify(rebuilt));
      }
    } catch (_) {}
  } catch (e) {
    console.warn('[f12] get-play-cost failed', e);
  }
}
// Tween a number element from `from` to `to` over `dur` ms with tick sound.
function _f12AnimBalanceTo(el, from, to, dur, onDone) {
  if (!el) { if (onDone) onDone(); return; }
  const t0 = performance.now();
  let lastTick = from;
  function step(t) {
    const k = Math.min(1, (t - t0) / dur);
    const eased = 1 - Math.pow(1 - k, 2); // ease-out quad
    const cur = Math.round(from + (to - from) * eased);
    if (cur !== lastTick) {
      el.textContent = cur;
      try { SFX.play(280 + (lastTick % 50) * 4, 0.022, 0.04, 'square', 0); } catch(_){}
      lastTick = cur;
    }
    if (k < 1) requestAnimationFrame(step);
    else {
      el.textContent = to;
      el.classList.remove('is-tick');
      // Force reflow then re-add to retrigger
      void el.offsetWidth;
      el.classList.add('is-tick');
      setTimeout(() => el.classList.remove('is-tick'), 500);
      if (onDone) onDone();
    }
  }
  requestAnimationFrame(step);
}

// Insufficient feedback (shake + DENIED stamp + sound)
function _f12DenyFeedback() {
  SFX.play(180, 0.12, 0.08, 'square', -400);
  setTimeout(() => SFX.play(140, 0.18, 0.08, 'square', -400), 100);
  const heroBtn = document.getElementById('f12e-hero-btn');
  if (heroBtn) {
    heroBtn.classList.add('is-insufficient');
    setTimeout(() => heroBtn.classList.remove('is-insufficient'), 600);
  }
  const bar = document.getElementById('f12e-balance-bar');
  if (bar) {
    bar.classList.add('is-denying');
    setTimeout(() => bar.classList.remove('is-denying'), 500);
  }
  const stamp = document.getElementById('f12e-denied-stamp');
  if (stamp) {
    stamp.classList.remove('is-show');
    void stamp.offsetWidth;
    stamp.classList.add('is-show');
    setTimeout(() => stamp.classList.remove('is-show'), 1000);
  }
}

window._f12ConfirmPlay = async function() {
  const W = window.Wallet;
  const connected = !!(W && W.isConnected && W.isConnected());

  // ── WALLET CONNECTED: server-authoritative path (register-play) ─────
  if (connected && window.SupabaseSync && typeof window.SupabaseSync.invoke === 'function') {
    const addr = W.getAddress && W.getAddress();
    if (!addr) {
      if (typeof logEvent === 'function') logEvent('✗ No wallet address', 'warn');
      _f12DenyFeedback();
      return;
    }
    // Block double-click while server call in flight
    if (window._f12PlayInFlight) return;
    window._f12PlayInFlight = true;
    try {
      const resp = await window.SupabaseSync.invoke('register-play', { wallet: addr.toLowerCase() });
      const data = resp && resp.data;
      // ── FALLBACK: edge fn not yet deployed (404) → local charge ──
      // Allows existing local pricing/charge flow to continue working
      // until SEC-5 edge functions are deployed in Supabase Dashboard.
      if (resp && resp.status === 404) {
        if (typeof logEvent === 'function') logEvent('⚠ register-play edge fn missing — using local fallback', 'warn');
        _f12LocalFallbackPlay();
        return;
      }
      if (!resp || !resp.ok || !data || data.ok !== true) {
        // Insufficient balance from server
        if (data && data.error === 'Insufficient balance') {
          if (typeof logEvent === 'function') logEvent(`✗ Need ${data.cost} RONKE (have ${data.balance})`, 'warn');
          _f12DenyFeedback();
        } else {
          if (typeof logEvent === 'function') logEvent(`✗ Play registration failed: ${(data && data.error) || 'unknown'}`, 'warn');
          _f12DenyFeedback();
        }
        return;
      }
      const cost = Number(data.cost) || 0;
      const fromBal = (typeof _ronkeBalance === 'number') ? Math.floor(_ronkeBalance) : 0;
      const toBal = Number(data.balance);
      // Sync local balance with server-authoritative value
      _ronkeBalance = toBal;
      if (typeof window.updateRonkeBadge === 'function') window.updateRonkeBadge();
      if (typeof logEvent === 'function') {
        logEvent(cost === 0 ? '▶ PewPew Saga entry (FREE play)' : `▶ PewPew Saga entry (-${cost} RONKE) server-charged`, 'info');
      }
      const proceed = _f12_pendingProceed;
      _f12_pendingProceed = null;
      SFX.play(660, 0.08, 0.06, 'square', 300);
      const nowEl = document.getElementById('f12e-bal-now');
      const dur = cost > 0 ? Math.min(900, 200 + cost * 30) : 0;
      function finish() {
        const ov = document.getElementById('f12-entry-overlay');
        if (ov) ov.classList.remove('active');
        SFX.play(900, 0.10, 0.06, 'square', 500);
        if (typeof proceed === 'function') setTimeout(proceed, 80);
        else if (typeof _f12_realGotoF12 === 'function') setTimeout(_f12_realGotoF12, 80);
      }
      if (dur > 0 && nowEl) {
        _f12AnimBalanceTo(nowEl, fromBal, toBal, dur, () => setTimeout(finish, 250));
      } else {
        finish();
      }
    } finally {
      window._f12PlayInFlight = false;
    }
    return;
  }

  // ── FALLBACK: anonymous (no wallet) — local log only, no real charge ──
  const d = window._f12CurrentCost();
  const cost = 0;  // anonymous = always free
  _f12LogPlay();
  const proceed = _f12_pendingProceed;
  _f12_pendingProceed = null;
  SFX.play(660, 0.08, 0.06, 'square', 300);
  const ov = document.getElementById('f12-entry-overlay');
  if (ov) ov.classList.remove('active');
  if (typeof logEvent === 'function') logEvent('▶ PewPew Saga entry (anonymous, no charge)', 'info');
  setTimeout(() => {
    if (typeof proceed === 'function') proceed();
    else if (typeof _f12_realGotoF12 === 'function') _f12_realGotoF12();
  }, 80);
};

// Local-charge fallback when server fn unavailable (404 from register-play).
// Mirrors the legacy pre-SEC-5 logic: deduct from _ronkeBalance, log locally.
function _f12LocalFallbackPlay() {
  const d = window._f12CurrentCost();
  const cost = d.cost;
  if (cost > 0 && (typeof _ronkeBalance !== 'number' || _ronkeBalance < cost)) {
    _f12DenyFeedback();
    return;
  }
  const fromBal = (typeof _ronkeBalance === 'number') ? Math.floor(_ronkeBalance) : 0;
  const toBal = Math.max(0, fromBal - cost);
  if (cost > 0 && typeof _ronkeBalance === 'number') {
    _ronkeBalance = Math.max(0, _ronkeBalance - cost);
    if (typeof window.updateRonkeBadge === 'function') window.updateRonkeBadge();
    if (typeof saveProfile === 'function') saveProfile();
    if (typeof logEvent === 'function') logEvent(`▶ PewPew Saga entry (-${cost} RONKE) local fallback`, 'info');
  }
  _f12LogPlay();
  const proceed = _f12_pendingProceed;
  _f12_pendingProceed = null;
  SFX.play(660, 0.08, 0.06, 'square', 300);
  const nowEl = document.getElementById('f12e-bal-now');
  const dur = cost > 0 ? Math.min(900, 200 + cost * 30) : 0;
  function finish() {
    const ov = document.getElementById('f12-entry-overlay');
    if (ov) ov.classList.remove('active');
    SFX.play(900, 0.10, 0.06, 'square', 500);
    if (typeof proceed === 'function') setTimeout(proceed, 80);
    else if (typeof _f12_realGotoF12 === 'function') setTimeout(_f12_realGotoF12, 80);
  }
  if (dur > 0 && nowEl) {
    _f12AnimBalanceTo(nowEl, fromBal, toBal, dur, () => setTimeout(finish, 250));
  } else {
    finish();
  }
}
window._f12CancelPlay = function() {
  const ov = document.getElementById('f12-entry-overlay');
  if (ov) ov.classList.remove('active');
  _f12_pendingProceed = null;
  SFX.play(400, 0.06, 0.04, 'square', -200);
};
// Wrap window.gotoF12 (set by floor12_merge.js) — runs after DOMContentLoaded.
document.addEventListener('DOMContentLoaded', () => {
  setTimeout(() => {
    if (typeof window.gotoF12 === 'function' && !_f12_realGotoF12) {
      _f12_realGotoF12 = window.gotoF12;
      window.gotoF12 = function() { _showF12EntryPopup(_f12_realGotoF12); };
    }
  }, 500);
});

// ── NFT Perks Panel (NFT-G) ─────────────────────────────────────────
window.openNftPerksPanel = function openNftPerksPanel() {
  const ov = document.getElementById('nft-perks-overlay');
  if (!ov) return;
  ov.classList.add('active');
  _renderNftPerksStatus();
  SFX.play(600, 0.08, 0.04, 'square', 200);
};
window.closeNftPerksPanel = function closeNftPerksPanel() {
  const ov = document.getElementById('nft-perks-overlay');
  if (ov) ov.classList.remove('active');
  SFX.play(400, 0.06, 0.04, 'square', -200);
};
function _renderNftPerksStatus() {
  const el = document.getElementById('npp-status');
  if (!el) return;
  const W = window.Wallet;
  if (!W || !W.isConnected || !W.isConnected()) {
    el.innerHTML = 'Connect your wallet to see your status';
    el.className = 'npp-status npp-status-disconnected';
    return;
  }
  el.innerHTML = '⏳ Checking NFT status...';
  el.className = 'npp-status';
  if (!W.getNftHoldStatus) {
    el.innerHTML = '⚠ NFT status helper not available';
    el.className = 'npp-status npp-status-error';
    return;
  }
  W.getNftHoldStatus().then(d => {
    // Re-check panel is still open before mutating DOM.
    const ov = document.getElementById('nft-perks-overlay');
    if (!ov || !ov.classList.contains('active')) return;
    if (!d || !d.ok) {
      el.innerHTML = '⚠ Could not verify NFT status — try again later';
      el.className = 'npp-status npp-status-error';
      return;
    }
    const total = d.totalCount, elig = d.eligibleCount;
    if (total === 0) {
      el.innerHTML = '✗ No RONKE NFTs in this wallet · <a href="https://marketplace.skymavis.com/collections/ronkeverse" target="_blank">Get one →</a>';
      el.className = 'npp-status npp-status-none';
    } else if (elig === 0) {
      const ageH = Math.floor(d.oldestHoldSeconds / 3600);
      const hLeft = Math.max(0, 24 - ageH);
      el.innerHTML = `⏰ <strong>${total}</strong> NFT held — bonuses unlock in <strong>~${hLeft}h</strong> (24h hold required)`;
      el.className = 'npp-status npp-status-pending';
    } else {
      el.innerHTML = `✓ <strong>${elig} / ${total}</strong> NFT${elig > 1 ? 's' : ''} eligible — all bonuses ACTIVE`;
      el.className = 'npp-status npp-status-active';
    }
  }).catch(() => {
    el.innerHTML = '⚠ Network error verifying NFT status';
    el.className = 'npp-status npp-status-error';
  });
}

// ── NFT-DEATH repeatable trophy mission (added 2026-06-26) ───────────────
// Trofėjus už NFT unitų mirtis. Slenksčiai: 10, 21, 32 … = 11·n − 1 (žingsnis +11).
// VISKAS AUTHORITATIVE iš serverio — NEAPGAUNAMA:
//   • deaths = DISTINCT žuvę NFT (battle_sessions, server-side, tik savo token'ai)
//   • nextTier / claimableNow = skaitoma TIESIAI iš kontrakto (claimedAchievement)
// Joks kliento state (Profile.trophyClaims) sprendimuose → cross-device saugu, jokio cheat.
function _deathTrophyThreshold(n) { return 11 * n - 1; }
// 💀 Death-progress fetch su 5-min CACHE — trofėjų panelė re-renderinasi kas 1.5s; BE cache tai kviestų backend
// (mirčių skaičius + on-chain multicall) kas 1.5s. Su cache → backend kviečiamas daugiausiai 1× per 5 min.
let _deathProgCache = null;   // { wallet, at, res }
const _DEATH_PROG_TTL = 5 * 60 * 1000;   // 5 min (user prašymas: ne kas sekundę, o kas 5 min)
function _invalidateDeathProgCache() { _deathProgCache = null; }
function _fetchDeathProgress() {
  let wallet = '';
  try { wallet = (window.Wallet && window.Wallet.getAddress && window.Wallet.getAddress()) || ''; } catch (_) {}
  const now = Date.now();
  if (_deathProgCache && _deathProgCache.wallet === wallet && (now - _deathProgCache.at) < _DEATH_PROG_TTL) {
    return Promise.resolve(_deathProgCache.res);   // iš cache — JOKIO backend kvietimo
  }
  return window.SupabaseSync.validateAchievement('T_deaths_progress').then(res => {
    _deathProgCache = { wallet: wallet, at: Date.now(), res: res };
    return res;
  });
}
function _appendDeathTrophyCard(grid) {
  const card = document.createElement('div');
  card.className = 'tier-card tier-deaths';
  card.innerHTML = `
    <div class="tier-card-header">
      <span class="tier-card-icon">💀</span>
      <span class="tier-card-title">NFT DEATHS</span>
      <span class="tier-card-progress">…</span>
    </div>
    <div class="tier-reqs"><div class="tier-req"><div class="tier-req-row">
      <span class="tier-req-text">Loading death count…</span></div></div></div>
    <div class="tier-actions"></div>`;
  grid.insertBefore(card, grid.firstChild);   // 💀 misija PIRMA panelėj (user prašymas) — ne pabaigoj

  const progEl = card.querySelector('.tier-card-progress');
  const reqsEl = card.querySelector('.tier-reqs');
  const actEl  = card.querySelector('.tier-actions');

  const connected = window.Wallet && window.Wallet.isConnected && window.Wallet.isConnected();
  if (!connected || !window.SupabaseSync || typeof window.SupabaseSync.validateAchievement !== 'function') {
    progEl.textContent = '—';
    reqsEl.innerHTML = `<div class="tier-req"><div class="tier-req-row"><span class="tier-req-text">Connect wallet to view your NFT death progress.</span></div></div>`;
    return;
  }

  _fetchDeathProgress().then(res => {
    const d = res && res.data;
    if (!res || !res.ok || !d || typeof d.deaths !== 'number') {
      // Backend dar neturi T_deaths kelio (sena versija) → slepiam kortelę ŠVARIAI,
      // kad deploy būtų saugus bet kuria tvarka (frontend gali eit prieš backend).
      const errTxt = (d && d.error) || '';
      if (/unknown achievement/i.test(errTxt) || (res && res.status === 400)) {
        // Backend dar nepalaiko (deploy laukia) → rodom MATOMĄ „activating soon" kortelę
        // (ne klaida, ne paslėpta). Pilnai suveiks tą sekundę, kai bus deploy'intas backend.
        progEl.textContent = 'soon';
        reqsEl.innerHTML = `<div class="tier-req"><div class="tier-req-row"><span class="tier-req-text">Earn a trophy for every +11 NFT unit deaths (10 → 21 → 32 …).</span></div></div>`;
        actEl.className = 'tier-actions tier-actions-locked';
        actEl.innerHTML = `<button class="tier-claim-btn disabled"><span class="tcb-lock">🔒 ACTIVATING SOON</span></button>`;
        return;
      }
      progEl.textContent = '—';
      reqsEl.innerHTML = `<div class="tier-req"><div class="tier-req-row"><span class="tier-req-text">Could not load deaths (${errTxt || (res && res.status) || 'error'}).</span></div></div>`;
      return;
    }
    const deaths = d.deaths;
    const nextTier = d.nextTier || 1;
    const nextThreshold = (typeof d.nextThreshold === 'number') ? d.nextThreshold : _deathTrophyThreshold(nextTier);
    const onchainOk = d.onchainOk !== false;
    const claimable = !!d.claimableNow && onchainOk;
    const claimedCount = Math.max(0, nextTier - 1);
    const prevThreshold = claimedCount >= 1 ? _deathTrophyThreshold(claimedCount) : 0;
    const span = Math.max(1, nextThreshold - prevThreshold);
    const pct = Math.max(0, Math.min(100, Math.round(((deaths - prevThreshold) / span) * 100)));

    progEl.textContent = `${claimedCount} claimed`;
    progEl.className = 'tier-card-progress' + (claimable ? ' complete' : '');
    reqsEl.innerHTML = `
      <div class="tier-req ${claimable ? 'met' : ''}">
        <div class="tier-req-row">
          <span class="tier-req-check">${claimable ? '✓' : '○'}</span>
          <span class="tier-req-text">Trophy #${nextTier}: ${nextThreshold} NFT unit deaths</span>
          <span class="tier-req-progress">${_formatProgress(deaths, nextThreshold)}</span>
        </div>
        <div class="tier-req-bar"><div class="tier-req-bar-fill" style="width:${pct}%"></div></div>
      </div>
      <div class="tier-req" style="opacity:.7"><div class="tier-req-row"><span class="tier-req-text">+11 deaths per trophy (10 → 21 → 32 …). Repeatable forever.</span></div></div>`;

    if (claimable) {
      actEl.className = 'tier-actions';
      actEl.innerHTML = `<button class="tier-claim-btn enabled" data-death-tier="${nextTier}">CLAIM NFT (Trophy #${nextTier})</button>`;
      actEl.querySelector('button').addEventListener('click', () => {
        closeTrophyPanel();
        setTimeout(() => showTrophyModal({
          id: 'T_deaths_' + nextTier,
          label: 'NFT DEATHS — Trophy #' + nextTier,
          desc: `Claim your trophy for ${nextThreshold} fallen NFT units. The next one unlocks at ${_deathTrophyThreshold(nextTier + 1)} total deaths.`,
        }), 200);
      });
    } else if (!onchainOk) {
      actEl.className = 'tier-actions tier-actions-locked';
      actEl.innerHTML = `<button class="tier-claim-btn disabled">
        <span class="tcb-lock">⏳ On-chain check unavailable</span>
        <span class="tcb-hint">${deaths} NFT deaths · reopen panel to retry</span></button>`;
    } else {
      actEl.className = 'tier-actions tier-actions-locked';
      actEl.innerHTML = `<button class="tier-claim-btn disabled">
        <span class="tcb-lock">🔒 ${Math.max(0, nextThreshold - deaths)} more NFT deaths</span>
        <span class="tcb-hint">${deaths}/${nextThreshold} — next is Trophy #${nextTier}</span></button>`;
    }
  }).catch(err => {
    progEl.textContent = '—';
    reqsEl.innerHTML = `<div class="tier-req"><div class="tier-req-row"><span class="tier-req-text">Network error loading deaths.</span></div></div>`;
    console.warn('[death trophy]', err);
  });
}

function renderTrophyPanel() {
  const grid = document.getElementById('trophy-tier-grid');
  if (!grid) return;
  grid.innerHTML = '';

  const statuses = window.getTrophyTierStatus ? window.getTrophyTierStatus() : [];

  for (const tier of statuses) {
    const card = document.createElement('div');
    card.className = `tier-card ${_TIER_CLASS[tier.id] || ''} ${tier.eligible ? 'tier-eligible' : ''} ${tier.claimed ? 'tier-claimed' : ''}`;

    const metCount = tier.requirements.filter(r => r.met).length;
    const reqHtml = tier.requirements.map(r => {
      const pct = Math.min(100, Math.round((r.currentValue / r.threshold) * 100));
      return `
      <div class="tier-req ${r.met ? 'met' : ''}">
        <div class="tier-req-row">
          <span class="tier-req-check">${r.met ? '✓' : '○'}</span>
          <span class="tier-req-text">${r.label}</span>
          <span class="tier-req-progress">${_formatProgress(r.currentValue, r.threshold)}</span>
        </div>
        <div class="tier-req-bar"><div class="tier-req-bar-fill" style="width:${pct}%"></div></div>
      </div>
    `;}).join('');

    let actionHtml;
    if (tier.claimed) {
      const txHash = (Profile.trophyClaims && Profile.trophyClaims[tier.id] && Profile.trophyClaims[tier.id].txHash) || '';
      const link = txHash ? `<a href="https://app.roninchain.com/tx/${txHash}" target="_blank" class="tier-claimed-link">view tx</a>` : '';
      actionHtml = `
        <div class="tier-actions">
          <button class="tier-claim-btn claimed">✓ CLAIMED</button>
          ${link}
        </div>`;
    } else if (tier.eligible) {
      actionHtml = `
        <div class="tier-actions">
          <button class="tier-claim-btn enabled" data-tier="${tier.id}">CLAIM NFT</button>
        </div>`;
    } else {
      actionHtml = `
        <div class="tier-actions tier-actions-locked">
          <button class="tier-claim-btn disabled">
            <span class="tcb-lock">🔒 1 PEWPEW TROPHY LOCKED</span>
            <span class="tcb-hint">Complete ${metCount}/${tier.requirements.length} mission tasks to unlock mint</span>
          </button>
        </div>`;
    }

    card.innerHTML = `
      <div class="tier-card-header">
        <span class="tier-card-icon">${_TIER_ICONS[tier.id] || '●'}</span>
        <span class="tier-card-title">${tier.label}</span>
        <span class="tier-card-progress ${metCount === tier.requirements.length ? 'complete' : ''}">${metCount}/${tier.requirements.length}</span>
      </div>
      <div class="tier-reqs">${reqHtml}</div>
      ${actionHtml}
    `;

    grid.appendChild(card);
  }

  // NFT-DEATH repeatable mission card (server-authoritative death count).
  _appendDeathTrophyCard(grid);

  // Phase 15 — append "COMING SOON" teaser card to signal project growth
  const teaser = document.createElement('div');
  teaser.className = 'tier-card tier-coming-soon';
  teaser.innerHTML = `
    <div class="tier-card-header">
      <span class="tier-card-icon">◇</span>
      <span class="tier-card-title">COMING SOON</span>
      <span class="tier-card-progress tcs-badge">?/?</span>
    </div>
    <div class="tcs-body">
      <div class="tcs-line">New missions added soon</div>
      <div class="tcs-line"><strong>AGE OF RONKE</strong> opening soon</div>
      <div class="tcs-line">More games joining the lineup over time</div>
      <div class="tcs-line">All games connected into one shared <strong>0x-pewpew</strong> universe</div>
    </div>
    <div class="tier-actions">
      <a class="tier-claim-btn tcs-btn" href="https://discord.com/invite/XgVbrr7wfW" target="_blank" rel="noopener noreferrer">GOT QUESTIONS? JOIN DISCORD</a>
    </div>
  `;
  grid.appendChild(teaser);

  // Wire claim buttons (single delegation)
  grid.querySelectorAll('.tier-claim-btn.enabled').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const tierId = e.target.getAttribute('data-tier');
      const tier = TROPHY_TIERS.find(t => t.id === tierId);
      if (tier) {
        closeTrophyPanel();
        // Show claim modal — reuse existing flow
        setTimeout(() => showTrophyModal({ id: tier.id, label: tier.label, desc: tier.desc }), 200);
      }
    });
  });
}

function _formatProgress(current, threshold) {
  // Cap display at 999k for readability
  const fmt = (n) => n >= 1000 ? (n >= 1000000 ? (n/1000000).toFixed(1)+'m' : (n/1000).toFixed(1)+'k') : n;
  return `${fmt(current)}/${fmt(threshold)}`;
}

function showAchievementPopup(a) {
  const popup = document.getElementById('achievement-popup');
  if (!popup) return;
  document.getElementById('ach-label-text').textContent = a.label;
  document.getElementById('ach-desc-text').textContent = a.desc;
  popup.classList.add('visible');
  SFX.play(880, 0.1, 0.05, 'square');
  setTimeout(() => SFX.play(1320, 0.15, 0.06, 'square'), 100);
  logEvent(`ACHIEVEMENT: ${a.label}`, 'info');
  setTimeout(() => popup.classList.remove('visible'), 3500);
}


// Generic slide-in notification (top-center, auto-dismiss).
let _notifTimer = null;
function showGameNotification(title, desc, color) {
  color = color || '#00f5ff';
  const el = document.getElementById('game-notif');
  if (!el) return;
  el.style.borderColor = color;
  el.style.boxShadow = `0 0 24px ${color}44`;
  const t = document.getElementById('game-notif-title');
  const d = document.getElementById('game-notif-desc');
  if (t) { t.textContent = title; t.style.color = color; t.style.textShadow = `0 0 8px ${color}`; }
  if (d) d.textContent = desc;
  el.classList.add('visible');
  if (_notifTimer) clearTimeout(_notifTimer);
  _notifTimer = setTimeout(() => el.classList.remove('visible'), 3200);
}

