        ctx.fillStyle = '#1a1f28';
        ctx.fillRect(barX, barY, barW, barH);
        ctx.fillStyle = _ready ? '#6eff8a' : '#ffcf5c';
        ctx.fillRect(barX, barY, Math.max(0, barW * cdFrac), barH);
