    ctx.globalAlpha = 0.5 + pulse * 0.38;
    ctx.strokeStyle = color; ctx.lineWidth = 2; ctx.shadowBlur = 16;
    const lx = (hitUnit.x + 0.5) * CELL, ly = (hitUnit.y + 0.5) * CELL, d = CELL * 0.27;
    ctx.beginPath();
    ctx.moveTo(lx - d, ly - d); ctx.lineTo(lx + d, ly + d);
    ctx.moveTo(lx + d, ly - d); ctx.lineTo(lx - d, ly + d);
